import { api, getOwnerUnlockToken } from '@/lib/http';
import {
  createVisibilityPayload,
  normalizeAdminFeatureVisibility,
  type AdminFeatureVisibilityState,
} from '@/lib/adminFeatureVisibility';

export type OwnerStatus = {
  mode?: 'NORMAL' | 'READ_ONLY' | 'LOCKDOWN' | string;
  maintenance?: boolean;
  ownerUnlocked?: boolean;
  ownerUnlockExpiresAt?: string | null;
  externalFetch?: boolean;
  aiAutoPublish?: boolean;
};

export type OwnerKeyStatus = {
  unlocked?: boolean;
  expiresAt?: string | null;
  ownerUnlocked?: boolean;
  ownerUnlockExpiresAt?: string | null;
  ttlMs?: number;
  ttlSec?: number;
  unlockToken?: string;
  [key: string]: any;
};

export type SystemState = {
  mode?: 'NORMAL' | 'READ_ONLY' | 'LOCKDOWN' | string;
  maintenance?: boolean;
  externalFetch?: boolean;
  aiAutoPublish?: boolean;
  [key: string]: any;
};

// Owner key
export async function getOwnerKeyStatus(): Promise<OwnerKeyStatus> {
  return api<OwnerKeyStatus>('/owner/key/status');
}

export async function unlockOwnerKey(pin: string): Promise<OwnerKeyStatus> {
  return api<OwnerKeyStatus>('/owner/key/unlock', {
    method: 'POST',
    json: { pin },
  });
}

export async function lockOwnerKey(): Promise<{ ok?: boolean } & Record<string, any>> {
  return api('/owner/key/lock', {
    method: 'POST',
    ownerUnlockToken: getOwnerUnlockToken(),
  });
}

// Admin settings (dangerous: requires owner unlock)
export async function getAdminSettings(): Promise<any> {
  return api('/admin/settings');
}

export async function putAdminSettings(patch: any): Promise<any> {
  return api('/admin/settings', {
    method: 'PATCH',
    json: patch || {},
    ownerUnlockToken: getOwnerUnlockToken(),
  });
}

export async function getSystemState(): Promise<SystemState> {
  return api<SystemState>('/admin/system/state');
}

export async function updateSystemState(payload: Partial<SystemState>): Promise<SystemState> {
  return api<SystemState>('/admin/system/state', {
    method: 'PUT',
    json: payload || {},
    ownerUnlockToken: getOwnerUnlockToken(),
  });
}

export async function lockdown(): Promise<any> {
  return api('/admin/system/lockdown', {
    method: 'POST',
    ownerUnlockToken: getOwnerUnlockToken(),
  });
}

export async function reactivate(): Promise<any> {
  return api('/admin/system/reactivate', {
    method: 'POST',
    ownerUnlockToken: getOwnerUnlockToken(),
  });
}

export async function health(): Promise<any> {
  return api('/system/health');
}

export async function getRecentAudit(limit = 30): Promise<any> {
  return api(`/audit/recent?limit=${encodeURIComponent(String(limit))}`);
}

export type SnapshotItem = {
  id: string;
  createdAt?: string;
  label?: string;
  reason?: string;
  mode?: string;
  checksum?: string;
  actor?: string;
  [key: string]: any;
};

export type DeployEventItem = {
  id: string;
  happenedAt?: string;
  provider?: string;
  service?: string;
  environment?: string;
  status?: string;
  deployId?: string;
  url?: string;
  commitSha?: string;
  branch?: string;
  message?: string;
  author?: string;
  [key: string]: any;
};

export type VersionTimeline = {
  ok?: boolean;
  deploys: DeployEventItem[];
  snapshots: SnapshotItem[];
};

// Back-compat: older UI panels expect a version timeline feed.
// The real backend contract we are standardizing on is snapshots under:
//   GET /api/admin/system/snapshots?limit=..
// Deploy history is not currently surfaced here, so deploys remain empty.
export async function getVersionTimeline(limit = 50): Promise<VersionTimeline> {
  const r = await listSnapshots(limit);
  const items = Array.isArray((r as any)?.items) ? (r as any).items : Array.isArray(r) ? (r as any) : [];
  return { ok: true, deploys: [], snapshots: items as SnapshotItem[] };
}

export async function exportVersionTimeline(limit = 500): Promise<VersionTimeline> {
  return getVersionTimeline(limit);
}

export async function getSnapshot(id: string): Promise<SnapshotItem> {
  if (!id) return { id };
  const r = await listSnapshots(200);
  const items = Array.isArray((r as any)?.items) ? (r as any).items : Array.isArray(r) ? (r as any) : [];
  const found = (items as SnapshotItem[]).find((s) => s?.id === id);
  return found || { id };
}

export async function rollbackDryRun(_id: string): Promise<any> {
  const err: any = new Error('Rollback preview is not supported by this backend route');
  err.status = 501;
  err.response = { status: 501 };
  return Promise.reject(err);
}

function normalizeId(raw: any): string {
  const id = raw?.id ?? raw?._id ?? raw?.snapshotId ?? raw?.deployId;
  return typeof id === 'string' ? id : id ? String(id) : '';
}

function normalizeSnapshot(raw: any): SnapshotItem {
  return {
    id: normalizeId(raw),
    createdAt: raw?.createdAt ?? raw?.created_at ?? raw?.happenedAt ?? raw?.ts ?? raw?.time,
    label: raw?.label ?? raw?.note,
    reason: raw?.reason,
    mode: raw?.mode,
    checksum: raw?.checksum,
    actor: raw?.actor,
    ...raw,
  };
}

function normalizeDeploy(raw: any): DeployEventItem {
  return {
    id: normalizeId(raw),
    happenedAt: raw?.happenedAt ?? raw?.createdAt,
    provider: raw?.provider,
    service: raw?.service,
    environment: raw?.environment,
    status: raw?.status,
    deployId: raw?.deployId,
    url: raw?.url,
    commitSha: raw?.commitSha,
    branch: raw?.branch,
    message: raw?.message,
    author: raw?.author,
    ...raw,
  };
}

export async function createSnapshot(payload: { label?: string; reason?: string }): Promise<SnapshotItem> {
  const raw: any = await api('/admin/system/snapshots', {
    method: 'POST',
    json: { label: payload?.label, reason: payload?.reason },
    ownerUnlockToken: getOwnerUnlockToken(),
  });
  return normalizeSnapshot(raw?.snapshot ?? raw);
}

export async function listSnapshots(limit = 20): Promise<{ items: SnapshotItem[] } | SnapshotItem[]> {
  const raw: any = await api(`/admin/system/snapshots?limit=${encodeURIComponent(String(limit))}`);
  const items = Array.isArray(raw?.items) ? raw.items.map(normalizeSnapshot) : Array.isArray(raw) ? raw.map(normalizeSnapshot) : [];
  return { items };
}

export async function rollbackApply(snapshotId: string): Promise<any> {
  return api('/admin/system/rollback', {
    method: 'POST',
    json: { snapshotId },
    ownerUnlockToken: getOwnerUnlockToken(),
  });
}

export async function getAdminFeatureVisibility(): Promise<AdminFeatureVisibilityState> {
  const response = await api('/admin/safe-owner-zone/feature-visibility');
  return normalizeAdminFeatureVisibility((response as any)?.visibility);
}

export async function putAdminFeatureVisibility(visibility: AdminFeatureVisibilityState): Promise<AdminFeatureVisibilityState> {
  const response = await api('/admin/safe-owner-zone/feature-visibility', {
    method: 'PUT',
    json: createVisibilityPayload(visibility),
  });
  return normalizeAdminFeatureVisibility((response as any)?.visibility);
}

import { useEffect, useState } from 'react';
import apiClient, { safeSettingsLoad } from '../lib/api';
import toast from 'react-hot-toast';
import html2pdf from 'html2pdf.js';
import {
  FaBrain, FaMoneyBill, FaUserShield
} from 'react-icons/fa';
import { useNavigate, Link } from 'react-router-dom';

// ✅ Admin Panel Lock Protection Wrapper
function useLockdownCheck(settings: any) {
  const navigate = useNavigate();
  useEffect(() => {
    if (settings.lockdown) {
      toast.error('🔒 Lockdown Mode is ON. Admin tools are restricted.');
      navigate('/admin/locked');
    }
  }, [settings.lockdown]);
}

type ZoneSectionProps = {
  title: string;
  icon: React.ReactNode;
  children: React.ReactNode;
};

const ZoneSection = ({ title, icon, children }: ZoneSectionProps) => {
  const [open, setOpen] = useState(false);
  return (
    <div className="bg-slate-900 text-white mb-4 rounded-xl shadow-lg">
      <button
        onClick={() => setOpen(!open)}
        className="w-full flex justify-between items-center px-6 py-3 text-left font-bold text-lg"
      >
        <div className="flex items-center gap-2">{icon} {title}</div>
        <span>{open ? '▲' : '▼'}</span>
      </button>
      {open && <div className="p-6 border-t border-slate-700">{children}</div>}
    </div>
  );
};

const defaultSettings = {
  aiTrainer: false,
  adsenseEnabled: false,
  voiceReader: true,
  lockdown: false,
  signatureLock: false,
  founderOnly: false,
};

const safeDefaults = {
  aiTrainer: false,
  adsenseEnabled: false,
  voiceReader: false,
  lockdown: false,
  signatureLock: false,
  founderOnly: false,
};

export default function AdminControlCenter() {
  const [settings, setSettings] = useState(defaultSettings);
  useLockdownCheck(settings);

  useEffect(() => {
    safeSettingsLoad({ skipProbe: true })
      .then((raw: any) => {
        const config = raw || defaultSettings;
        setSettings({
          aiTrainer: !!config.aiTrainer,
          adsenseEnabled: !!config.adsenseEnabled,
          voiceReader: !!config.voiceReader,
          lockdown: !!config.lockdown,
          signatureLock: !!config.signatureLock,
          founderOnly: !!config.founderOnly,
        });
        if (raw?._stub) {
          console.warn('[AdminControlCenter] settings stub active (route missing).');
        }
      })
      .catch(() => {
        toast.error('⚠️ Failed to load settings (stub defaults applied).');
        setSettings(defaultSettings);
      });
  }, []);

  const handleSave = () => {
    toast.promise(
      apiClient.post('/settings/save', settings),
      {
        loading: 'Saving settings...',
        success: '✅ Settings saved!',
        error: '❌ Failed to save settings.',
      }
    );
  };

  const handleReset = () => {
    setSettings(safeDefaults);
    toast.success('♻️ Settings reverted to Safe Mode');
  };

  const handleExportPDF = () => {
    const tempContainer = document.createElement('div');
    tempContainer.style.position = 'fixed';
    tempContainer.style.top = '20px';
    tempContainer.style.left = '20px';
    tempContainer.style.padding = '20px';
    tempContainer.style.background = 'white';
    tempContainer.style.color = 'black';
    tempContainer.style.fontFamily = 'Arial, sans-serif';
    tempContainer.style.fontSize = '14px';
    tempContainer.style.lineHeight = '1.5';
    tempContainer.innerHTML = `
      <h2 style="font-size:18px; margin-bottom:12px;">🧩 News Pulse Admin Settings</h2>
      <ul>
        <li><strong>AI Trainer:</strong> ${settings.aiTrainer ? 'Enabled ✅' : 'Disabled ❌'}</li>
        <li><strong>AdSense:</strong> ${settings.adsenseEnabled ? 'Enabled ✅' : 'Disabled ❌'}</li>
        <li><strong>Voice Reader:</strong> ${settings.voiceReader ? 'Enabled ✅' : 'Disabled ❌'}</li>
        <li><strong>Lockdown Mode:</strong> ${settings.lockdown ? 'Enabled 🔒' : 'Disabled 🔓'}</li>
        <li><strong>Signature Lock:</strong> ${settings.signatureLock ? 'Enabled ✍️' : 'Disabled ❌'}</li>
        <li><strong>Founder Only Mode:</strong> ${settings.founderOnly ? 'Active 👑' : 'Disabled ❌'}</li>
      </ul>
      <p style="margin-top:10px; font-size:12px; color:#444;">Exported on: ${new Date().toLocaleString()}</p>
    `;

    document.body.appendChild(tempContainer);

    html2pdf()
      .from(tempContainer)
      .set({
        margin: 0.5,
        filename: 'Admin_Settings_NewsPulse.pdf', /* internal filename kept; branding in UI updated */
        html2canvas: { scale: 2 },
        jsPDF: { orientation: 'portrait' },
      })
      .save()
      .then(() => {
        document.body.removeChild(tempContainer);
      });
  };

  return (
    <div className="min-h-screen bg-slate-900 p-4 md:p-6">
      <div className="max-w-5xl mx-auto">
        <div className="mb-6">
          <h1 className="text-4xl font-bold mb-3 text-white">🧩 Admin Control Center</h1>
          <p className="text-lg text-slate-200">Configure AI intelligence, founder controls, and monetization settings</p>
          <div className="mt-4 bg-blue-900/50 border border-blue-500 rounded-lg p-4">
            <p className="text-base text-white">
              📊 <strong className="text-white">Need system monitoring?</strong> Visit <Link to="/safeownerzone/founder" className="text-blue-300 underline hover:text-blue-200 font-semibold">Safe Zone</Link> for real-time metrics and detailed panels.
            </p>
          </div>
        </div>

        <div className="space-y-6">

          <ZoneSection title="AI Intelligence Zone" icon={<FaBrain />}>
            <label className="flex items-center gap-3 text-base text-white cursor-pointer">
              <input
                type="checkbox"
                checked={settings.aiTrainer}
                onChange={(e) => setSettings(prev => ({ ...prev, aiTrainer: e.target.checked }))}
                className="w-5 h-5"
              />
              <span className="font-medium">Enable AI Trainer (Beta)</span>
            </label>
          </ZoneSection>

          <ZoneSection title="Founder Control Zone" icon={<FaUserShield />}>
            <label className="flex items-center gap-3 text-base text-white mb-3 cursor-pointer">
              <input
                type="checkbox"
                checked={settings.lockdown}
                onChange={(e) => setSettings(prev => ({ ...prev, lockdown: e.target.checked }))}
                className="w-5 h-5"
              />
              <span className="font-medium">🔒 Enable Lockdown Mode</span>
            </label>

            <label className="flex items-center gap-3 text-base text-white mb-3 cursor-pointer">
              <input
                type="checkbox"
                checked={settings.signatureLock}
                onChange={(e) => setSettings(prev => ({ ...prev, signatureLock: e.target.checked }))}
                className="w-5 h-5"
              />
              <span className="font-medium">✍️ Enable Signature Lock</span>
            </label>

            <label className="flex items-center gap-3 text-base text-white mb-4 cursor-pointer">
              <input
                type="checkbox"
                checked={settings.founderOnly}
                onChange={(e) => setSettings(prev => ({ ...prev, founderOnly: e.target.checked }))}
                className="w-5 h-5"
              />
              <span className="font-medium">👑 Founder-Only Panel Mode</span>
            </label>

            <Link
              to="/safe-owner/update-pin"
              className="inline-block px-5 py-3 text-base font-semibold bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition shadow-lg"
            >
              🔁 Update Founder PIN
            </Link>
          </ZoneSection>

          <ZoneSection title="Monetization Zone" icon={<FaMoneyBill />}>
            <label className="flex items-center gap-3 text-base text-white cursor-pointer">
              <input
                type="checkbox"
                checked={settings.adsenseEnabled}
                onChange={(e) => setSettings(prev => ({ ...prev, adsenseEnabled: e.target.checked }))}
                className="w-5 h-5"
              />
              <span className="font-medium">Enable Google AdSense</span>
            </label>
          </ZoneSection>

          <div className="sticky bottom-0 bg-slate-800 p-6 rounded-xl shadow-2xl flex flex-wrap gap-4 justify-center items-center border-2 border-slate-700">
            <button onClick={handleSave} className="bg-green-600 px-8 py-3 rounded-lg text-lg font-bold text-white hover:bg-green-700 transition shadow-lg">
              💾 Save All
            </button>
            <button onClick={handleReset} className="bg-red-600 px-8 py-3 rounded-lg text-lg font-bold text-white hover:bg-red-700 transition shadow-lg">
              ♻️ Safe Mode
            </button>
            <button onClick={handleExportPDF} className="bg-blue-600 px-8 py-3 rounded-lg text-lg font-bold text-white hover:bg-blue-700 transition shadow-lg">
              📤 Export
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useEffect, useState } from "react";
import { adminApiClient as api } from "@/lib/adminApiClient";

export default function ArticlesList() {
  const [items, setItems] = useState<any[]>([]);
  const [q, setQ] = useState("");

  useEffect(() => { load(); }, []);
  async function load() {
    const { data } = await api.get('articles', { params: { q } });
    setItems(data.items);
  }

  return (
    <div>
      <h2>Articles</h2>
      <input placeholder="Search" value={q} onChange={(e)=>setQ(e.target.value)} />
      <button onClick={load}>Search</button>
      <ul>
        {items.map(a => <li key={a._id}>{a.title} — {a.status} — {a.language}</li>)}
      </ul>
    </div>
  );
}

import React, { useCallback, useEffect, useState } from "react";
import { AxiosError } from "axios";
import { api } from '@lib/api';

import { ADMIN_API_BASE } from '../../lib/adminApi';
const API_BASE = /\/api$/.test(ADMIN_API_BASE)
  ? ADMIN_API_BASE
  : `${ADMIN_API_BASE}/api`;

type ActivityData = {
  autoPublished: number;
  flagged: number;
  suggestedHeadlines: number;
  lastTrustUpdate: string;
};

const AIActivityLog: React.FC = () => {
  const [data, setData] = useState<ActivityData | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [note, setNote] = useState<string | null>(null);
  const [waking, setWaking] = useState(false);

  const coerceNumber = (v: any): number | null => {
    if (typeof v === 'number' && Number.isFinite(v)) return v;
    if (typeof v === 'string') {
      const n = Number(v.trim());
      return Number.isFinite(n) ? n : null;
    }
    return null;
  };

  const normalize = (raw: any): ActivityData | null => {
    const src = raw?.data && typeof raw.data === 'object' ? raw.data : raw;
    const autoPublished = coerceNumber(src?.autoPublished);
    const flagged = coerceNumber(src?.flagged);
    const suggestedHeadlines = coerceNumber(src?.suggestedHeadlines);
    let lastTrustUpdate: string | null = null;
    const ltu = src?.lastTrustUpdate;
    if (typeof ltu === 'string') lastTrustUpdate = ltu;
    else if (typeof ltu === 'number' && Number.isFinite(ltu)) {
      try { lastTrustUpdate = new Date(ltu).toISOString(); } catch {}
    }

    if (
      autoPublished !== null &&
      flagged !== null &&
      suggestedHeadlines !== null &&
      typeof lastTrustUpdate === 'string'
    ) {
      return { autoPublished, flagged, suggestedHeadlines, lastTrustUpdate };
    }
    return null;
  };

  const fetchData = useCallback(async () => {
    let didCancel = false;
    try {
      setLoading(true);
      setError(null);
      setNote(null);
      const json = await api.aiActivityLog() as any;
      const normalized = normalize(json);
      if (!normalized) {
        // Backend may not implement this endpoint in some environments (e.g., prod Render repo).
        // Degrade gracefully to an empty state instead of showing a red error.
        if (!didCancel) {
          setData({ autoPublished: 0, flagged: 0, suggestedHeadlines: 0, lastTrustUpdate: new Date(0).toISOString() });
          setNote('AI Activity endpoint not available on this backend. Showing an empty placeholder.');
        }
        return;
      }
      if (!didCancel) setData(normalized);
    } catch (err: any) {
      const ax = err as AxiosError<any>;
      const status = ax?.response?.status;
      const msg = (ax?.response?.data && (ax.response.data.message || ax.response.data.error)) || ax?.message || "Unknown error";
      if (didCancel) return;
      // If unauthorized, surface the error (interceptor will redirect to /auth in prod)
      if (status === 401) {
        setError(`⚠️ Failed to load AI activity (unauthorized). ${msg}`);
      } else {
        // Soft-fail to empty placeholder for 404/5xx or network/shape issues
        setData({ autoPublished: 0, flagged: 0, suggestedHeadlines: 0, lastTrustUpdate: new Date(0).toISOString() });
        setNote('AI Activity endpoint did not return expected data. Showing an empty placeholder.');
      }
    } finally {
      if (!didCancel) setLoading(false);
    }
    return () => { didCancel = true; };
  }, []);

  const wakeAndRetry = useCallback(async () => {
    try {
      setWaking(true);
      // Hit serverless health to wake upstream backend (Render may be sleeping)
      await fetch(`${API_BASE}/system/health`, { credentials: 'include' });
    } catch {
      // ignore; we'll still retry
    } finally {
      setWaking(false);
      fetchData();
    }
  }, [fetchData]);

  useEffect(() => {
    let cleanup: any;
    (async () => { cleanup = await fetchData(); })();
    return () => { if (typeof cleanup === 'function') cleanup(); };
  }, [fetchData]);

  return (
    <section className="p-5 md:p-6 bg-purple-50 dark:bg-purple-900/10 border border-purple-300 dark:border-purple-700 rounded-2xl shadow-inner max-h-[90vh] overflow-y-auto">
      <p className="text-green-600 dark:text-green-400 font-mono text-sm mb-2">
        ✅ AIActivityLog Loaded
      </p>
      <h2 className="text-xl font-bold text-purple-700 dark:text-purple-300 mb-3">
        🧠 AI Activity Log
      </h2>

      {loading ? (
        <div className="text-sm text-slate-500 dark:text-slate-400">
          ⏳ Loading real AI activity data...
        </div>
      ) : error ? (
        <div className="text-sm text-red-500 space-y-3">
          <div>{error}</div>
          <div className="flex gap-2">
            <button
              className="px-3 py-1.5 rounded-md bg-purple-600 text-white disabled:opacity-60"
              onClick={wakeAndRetry}
              disabled={waking}
            >{waking ? 'Waking…' : 'Wake backend then retry'}</button>
            <button
              className="px-3 py-1.5 rounded-md border border-purple-400 text-purple-700 dark:text-purple-300"
              onClick={fetchData}
              disabled={loading}
            >Retry</button>
          </div>
          <div className="text-xs text-slate-500 dark:text-slate-400">
            Tip: Ensure you are logged in via <a className="underline" href="/auth">/auth</a> and that the <code>/api</code> proxy can reach your backend.
            Quick check: <a className="underline" href="/system/health" target="_blank" rel="noreferrer">/system/health</a>
          </div>
        </div>
      ) : data ? (
        <ul className="text-sm space-y-2 text-slate-700 dark:text-slate-200 list-disc list-inside ml-2">
          <li>
            <strong>Auto-published:</strong>{" "}
            {data.autoPublished.toLocaleString()} stories today
          </li>
          <li>
            <strong>Flagged:</strong>{" "}
            {data.flagged.toLocaleString()} articles for review
          </li>
          <li>
            <strong>Suggestions:</strong>{" "}
            {data.suggestedHeadlines.toLocaleString()} trending headlines
          </li>
          <li>
            <strong>Last Trust Update:</strong> {data.lastTrustUpdate}
          </li>
          {note && (
            <li className="list-none text-xs italic text-slate-500 dark:text-slate-400 mt-1">
              {note}
            </li>
          )}
        </ul>
      ) : (
        <div className="text-sm text-gray-400 dark:text-gray-500">
          No activity data available yet.
          {note && (
            <div className="text-xs italic text-slate-500 dark:text-slate-400 mt-1">{note}</div>
          )}
        </div>
      )}
    </section>
  );
};

export default AIActivityLog;

// 📁 src/components/SafeZone/GlobalThreatScanner.tsx
import { useEffect, useState } from 'react';
import { fetchJson } from '@lib/fetchJson';
import {
  FaShieldAlt, FaLock, FaGlobe, FaCheckCircle, FaSyncAlt
} from 'react-icons/fa';

type ThreatStatus = {
  xssDetected: boolean;
  credentialsLeaked: boolean;
  ipReputationScore: number; // 0–100
  lastScan: string;
};

const getStatusBadge = (condition: boolean, label: string) => (
  <span
    className={`text-xs px-2 py-0.5 rounded-full font-semibold ${
      condition
        ? 'bg-red-100 text-red-700 dark:bg-red-800/30 dark:text-red-300'
        : 'bg-green-100 text-green-700 dark:bg-green-800/30 dark:text-green-300'
    }`}
  >
    {condition ? `⚠️ ${label}` : `✅ Secure`}
  </span>
);

const SECURITY_ENABLED = import.meta.env.VITE_SECURITY_SYSTEM_ENABLED !== 'false';

const GlobalThreatScanner = () => {
  const [data, setData] = useState<ThreatStatus | null>(null);
  const [loading, setLoading] = useState(true);
  const [lastError, setLastError] = useState<string | null>(null);

  const fetchThreatData = async () => {
    try {
      setLoading(true);
      setLastError(null);
      try {
        const json = await fetchJson<any>(`/system/threat-status`, { cache: 'no-store', timeoutMs: 15000 });
        if (!json || typeof json !== 'object') throw new Error('Invalid response');
        const normalized: ThreatStatus = {
          xssDetected: !!json.xssDetected,
          credentialsLeaked: !!json.credentialsLeaked,
          ipReputationScore: typeof json.ipReputationScore === 'number' ? json.ipReputationScore : 0,
          lastScan: typeof json.lastScan === 'string' ? json.lastScan : new Date().toISOString(),
        };
        setData(normalized);
      } catch (innerErr: any) {
        if (/route not found|404\b/i.test(innerErr?.message || '')) {
          console.warn('[GlobalThreatScanner] using secure stub (404)');
          setData({
            xssDetected: false,
            credentialsLeaked: false,
            ipReputationScore: 100,
            lastScan: new Date().toISOString(),
          });
          setLastError(null);
        } else {
          throw innerErr;
        }
      }
    } catch (err: any) {
      if (!lastError) console.error('[GlobalThreatScanner] fetch error:', err?.message || err);
      setData(null);
      setLastError(err?.message || 'Route not found');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (!SECURITY_ENABLED) {
      console.warn('[GlobalThreatScanner] disabled via VITE_SECURITY_SYSTEM_ENABLED=false');
      setData({
        xssDetected: false,
        credentialsLeaked: false,
        ipReputationScore: 100,
        lastScan: new Date().toISOString(),
      });
      setLoading(false);
      setLastError(null);
      return;
    }
    fetchThreatData(); // Initial fetch
    const interval = setInterval(fetchThreatData, 900000); // ⏱️ 15 min auto-refresh
    return () => clearInterval(interval);
  }, []);

  return (
    <section className="p-5 md:p-6 bg-fuchsia-50 dark:bg-fuchsia-950 border border-fuchsia-300 dark:border-fuchsia-700 rounded-2xl shadow-inner max-h-[90vh] overflow-y-auto">
