              {checks.compliance?.ptiFlags?.length > 0 && (
                <div className="mt-2 text-xs text-red-600">PTI flags: {checks.compliance.ptiFlags.join(' · ')} <button type="button" className="underline" onClick={addAttribution}>Add attribution</button></div>
              )}
              {checks.duplicate && checks.duplicate.score >= 0.78 && (
                <div className="mt-1 text-xs text-amber-700">Similar headline ({Math.round(checks.duplicate.score*100)}%). {checks.duplicate.closestId && <a className="underline" href={`/admin/articles/${checks.duplicate.closestId}`} target="_blank" rel="noreferrer">View closest</a>}</div>
              )}
              <div className="mt-2 flex gap-2 flex-wrap">
                {summary.length > 200 && <button type="button" onClick={trimSummaryTo160} className="btn-secondary text-[11px] px-2 py-1">Trim to ~160</button>}
                {(checks.compliance?.ptiFlags?.length ?? 0) > 0 && <button type="button" onClick={addAttribution} className="btn-secondary text-[11px] px-2 py-1">Add attribution</button>}
              </div>
            </div>
            <div>
              <div className="flex items-center justify-between gap-3">
                <label className="block text-sm font-medium">Content</label>
                <div className="text-xs text-slate-600">Words: {wordCount}</div>
              </div>
              {isSponsoredArticle ? (
                <div className="mb-3 rounded-lg border border-amber-200 bg-amber-50 px-3 py-2 text-xs text-amber-950">
                  Sponsored Article is on. This story will keep sponsor details separate from normal editorial content.
                </div>
              ) : null}
              <RichTextEditor
                value={content}
                onChange={setContent}
                placeholder="Write article content…"
              />
            </div>
          </div>
        </div>

        {/* RIGHT: Sidebar */}
        <aside className="md:col-span-4 space-y-3 md:h-full md:overflow-auto md:pr-2">
          <div className="card p-4">
            <div className="text-sm font-semibold mb-3">Publishing Settings</div>
            <div className="space-y-3">
              <div>
                <label className="block text-xs font-medium">Category</label>
                <select value={category} onChange={e=> setCategory(e.target.value)} className="w-full border px-2 py-2 rounded">
                  <option value="" disabled>Select category…</option>
                  {ARTICLE_CATEGORY_OPTIONS.map((opt) => (
                    <option key={opt.key} value={opt.key}>{opt.label}</option>
                  ))}
                </select>
                {roleCanPublish && publishEnabled && !String(category || '').trim() && ((title || '').trim() || (content || '').trim()) && (
                  <div className="mt-1 text-xs text-red-600">Category is required to publish.</div>
                )}
                {category && !categoryValidForPublish && (
                  <div className="mt-1 text-xs text-red-600">Category is not allowed. Please choose a supported category.</div>
                )}
              </div>

              {category === 'youth-pulse' && (
                <div>
                  <label className="block text-xs font-medium">Youth Pulse Track</label>
                  <select value={youthPulseTrack} onChange={e=> setYouthPulseTrack((e.target.value || '') as YouthPulseTrack | '')} className="w-full border px-2 py-2 rounded">
                    <option value="">Select Youth Pulse track…</option>
                    {YOUTH_PULSE_TRACK_OPTIONS.map((opt) => (
                      <option key={opt.value} value={opt.value}>{opt.label}</option>
                    ))}
                  </select>
                </div>
              )}

              <div className="pt-2 border-t border-slate-200">
                <div className="flex items-center justify-between gap-3 mb-2">
                  <div className="text-xs font-medium">Location Tags (Gujarat)</div>
                  <button
                    type="button"
                    className="text-[11px] text-slate-600 hover:text-slate-900 underline"
                    onClick={() => setLocationTagsCollapsed((v) => !v)}
                  >
                    {locationTagsCollapsed ? 'Show' : 'Minimize'}
                  </button>
                </div>
                {!locationTagsCollapsed && (
                  <>
                    <input
                      value={locationSearch}
                      onChange={(e) => setLocationSearch(e.target.value)}
                      className="w-full border px-2 py-2 rounded text-sm"
                      placeholder="Search districts / cities…"
                    />

                    <div className="mt-2 text-[11px] text-slate-600">Districts</div>
                    <div className="mt-1 flex flex-wrap gap-2">
                      {filteredDistricts.map((d) => {
                        const tag = `district:${d.slug}`;
                        const selected = selectedDistrictSlugs.has(d.slug);
                        return (
                          <button
                            type="button"
                            key={d.slug}
                            onClick={() => toggleGujaratLocationTag(tag)}
                            className={`px-2 py-1 rounded-full text-xs border ${selected ? 'bg-black text-white' : 'bg-white'}`}
                            title={tag}
                          >
                            {d.label}
                          </button>
                        );
                      })}
                    </div>

                    <div className="mt-3 text-[11px] text-slate-600">Cities</div>
                    <div className="mt-1 flex flex-wrap gap-2">
                      {filteredCities.map((c) => {
                        const tag = `city:${c.slug}`;
                        const selected = selectedCitySlugs.has(c.slug);
                        return (
                          <button
                            type="button"
                            key={c.slug}
                            onClick={() => toggleGujaratLocationTag(tag)}
                            className={`px-2 py-1 rounded-full text-xs border ${selected ? 'bg-black text-white' : 'bg-white'}`}
                            title={tag}
                          >
                            {c.label}
                          </button>
                        );
                      })}
                    </div>

                    <details className="mt-3">
                      <summary className="text-[11px] text-slate-600 cursor-pointer select-none">Other location fields (optional)</summary>
                      <div className="mt-2 space-y-2">
                        <input value={state} onChange={e=> setState(e.target.value)} className="w-full border px-2 py-2 rounded text-sm" placeholder="State" />
                        <input value={district} onChange={e=> setDistrict(e.target.value)} className="w-full border px-2 py-2 rounded text-sm" placeholder="District" />
                        <input value={city} onChange={e=> setCity(e.target.value)} className="w-full border px-2 py-2 rounded text-sm" placeholder="City" />
                      </div>
                    </details>
                  </>
                )}
              </div>
              <div>
                <label className="block text-xs font-medium">Language</label>
                <select value={language} onChange={e=> setLanguage(normalizeLang(e.target.value))} className="w-full border px-2 py-2 rounded" required>
                  <option value="en">English (en)</option>
                  <option value="hi">Hindi (hi)</option>
                  <option value="gu">Gujarati (gu)</option>
                </select>
                {!languagesQuery.isLoading && !languageValidForPublish && language && (
                  <div className="mt-1 text-xs text-red-600">Selected language is not supported.</div>
                )}
                {mixedScriptWarnings.length > 0 && (
                  <div className="mt-1 space-y-1">
                    {mixedScriptWarnings.map((m) => (
                      <div key={m} className="text-[11px] text-amber-700">{m}</div>
                    ))}
                  </div>
                )}
              </div>
              <div>
                <label className="block text-xs font-medium">Translation Group ID (optional)</label>
                <input
                  value={translationGroupId}
                  onChange={(e) => setTranslationGroupId(e.target.value)}
                  className="w-full border px-2 py-2 rounded text-sm"
                  placeholder="Leave empty to auto-generate on save"
                />
                {translationGroupId ? (
                  <div className="mt-1 text-[11px] text-slate-500">Group: {translationGroupId}</div>
                ) : (
                  <div className="mt-1 text-[11px] text-slate-500">Save once to generate a group id.</div>
                )}

                {translationGroupIdTrimmed ? (
                  <div className="mt-3 rounded border border-slate-200 bg-white p-3">
                    <div className="flex items-center justify-between gap-2">
                      <div className="text-xs font-semibold">Translations</div>
                      <div className="text-[11px] text-slate-600">
                        {groupStatus ? `Group Status: ${groupStatus}` : 'Group Status: —'}
                      </div>
                    </div>

                    <div className="mt-3 rounded border border-slate-200 bg-slate-50 p-3">
                      <div className="flex flex-wrap items-center justify-between gap-2">
                        <div>
                          <div className="text-[11px] uppercase tracking-wide text-slate-500">Article Mode</div>
                          <div className="text-sm font-semibold text-slate-900">
                            {isMasterArticle ? 'Master Article' : 'Linked Version'}
                          </div>
                        </div>
                        <div className="text-right">
                          <div className="text-[11px] uppercase tracking-wide text-slate-500">Linked Versions</div>
                          <div className="mt-1 flex flex-wrap justify-end gap-1">
                            {(['en', 'hi', 'gu'] as const).map((code) => {
                              const present = linkedVersionCodes.includes(code);
                              return (
                                <span
                                  key={`linked-${code}`}
                                  className={
                                    'inline-flex rounded-full border px-2 py-0.5 text-[11px] ' +
                                    (present ? 'border-slate-300 bg-white text-slate-800' : 'border-slate-200 bg-slate-100 text-slate-400')
                                  }
                                >
                                  {code.toUpperCase()}
                                </span>
                              );
                            })}
                          </div>
                        </div>
                      </div>

                      {isMasterArticle ? (
                        <div className="mt-3 rounded border border-emerald-200 bg-emerald-50 px-3 py-2 text-[11px] text-emerald-900">
                          Linked language versions stay separate. Publishing or changing media here does not update other stories.
                        </div>
                      ) : null}
                    </div>

                    {translationGroupQuery.isFetching ? (
                      <div className="mt-2 text-[11px] text-slate-500">Loading variants…</div>
                    ) : null}
                    {translationGroupQuery.isError ? (
                      <div className="mt-2 text-[11px] text-amber-700">Could not load translation variants.</div>
                    ) : null}

                    <div className="mt-3 rounded border border-slate-200 bg-slate-50 p-3">
                      <div className="text-xs font-semibold text-slate-900">Translation Sync Status</div>
                      <div className="mt-2 space-y-2">
                        {(['en', 'hi', 'gu'] as const).map((code) => {
                          const syncEntry = translationSyncStatuses[code];
                          const tone = getTranslationSyncTone(syncEntry.state);
                          const badgeCls = tone === 'ok'
                            ? 'border-emerald-200 bg-emerald-50 text-emerald-800'
                            : tone === 'warn'
                              ? 'border-amber-200 bg-amber-50 text-amber-800'
                              : 'border-slate-200 bg-white text-slate-700';

                          return (
                            <div key={`sync-${code}`} className="flex items-center justify-between gap-2 text-[11px]">
                              <span className="font-medium text-slate-700">{languageLabel(code)}</span>
                              <div className="flex items-center gap-2">
                                {syncEntry.detail ? <span className="text-slate-500">{syncEntry.detail}</span> : null}
                                <span className={`inline-flex rounded-full border px-2 py-0.5 ${badgeCls}`}>
                                  {getTranslationSyncLabel(syncEntry.state)}
                                </span>
                              </div>
                            </div>
                          );
                        })}
                      </div>
                    </div>

                    <div className="mt-2 space-y-2">
                      {(['en', 'hi', 'gu'] as const).map((code) => {
                        const v = translationVariants[code];
                        const badges = getTranslationBadges(v);
                        const isActive = language === code;
                        const idForVariant = v?._id || v?.id || null;
                        const isPresent = !!v;

                        return (
                          <div key={code} className="flex items-center justify-between gap-2">
                            <button
                              type="button"
                              className={
                                'px-2 py-1 rounded border text-xs ' +
                                (isActive ? 'bg-black text-white border-black' : 'bg-white hover:bg-slate-50')
                              }
                              onClick={() => {
                                if (isActive) return;
                                if (idForVariant) {
                                  navigate(`/admin/articles/${encodeURIComponent(String(idForVariant))}/edit`);
                                  return;
                                }
                              }}
                              title={idForVariant ? 'Open this language variant' : 'Variant not created yet'}
                            >
                              {code.toUpperCase()}
                            </button>

                            <div className="flex flex-wrap items-center justify-center gap-1">
                              {badges.map((badge) => {
                                const badgeCls = badge.tone === 'ok'
                                  ? 'border-emerald-200 bg-emerald-50 text-emerald-800'
                                  : badge.tone === 'warn'
                                    ? 'border-amber-200 bg-amber-50 text-amber-800'
                                    : 'border-slate-200 bg-slate-50 text-slate-700';

                                return (
                                  <span key={`${code}-${badge.text}`} className={`inline-flex px-2 py-0.5 rounded-full border text-[11px] ${badgeCls}`}>
                                    {badge.text}
                                  </span>
                                );
                              })}
                            </div>

                            <div className="flex items-center gap-2">
                              {idForVariant ? (
                                <button
                                  type="button"
                                  className="text-[11px] underline text-slate-700 hover:text-slate-900"
                                  onClick={() => navigate(`/admin/articles/${encodeURIComponent(String(idForVariant))}/edit`)}
                                  disabled={isActive}
                                >
                                  {isActive ? 'Editing' : 'Edit'}
                                </button>
                              ) : !isPresent ? (
                                <button
                                  type="button"
                                  className="text-[11px] underline text-slate-700 hover:text-slate-900"
                                  onClick={() => createLinkedTranslation(code)}
                                >
                                  Create
                                </button>
                              ) : (
                                <span className="text-[11px] text-slate-500">Covered</span>
                              )}
                            </div>
                          </div>
                        );
                      })}
                    </div>

                    <div className="mt-2 text-[11px] text-slate-600">
                      {isMasterArticle
                        ? 'Publishing this story affects only this story. Linked versions must be reviewed and published separately.'
                        : 'This linked version stays separate from the master article for publish and media changes.'}
                    </div>
                  </div>
                ) : null}

                {effectiveId && String(translationGroupId || '').trim() ? (
                  <div className="mt-2 flex flex-wrap gap-2">
                    {language !== 'hi' ? (
                      <button
                        type="button"
                        className="px-2 py-1 rounded border text-xs bg-white hover:bg-slate-50"
                        onClick={() => createLinkedTranslation('hi')}
                      >Create Hindi version</button>
                    ) : null}
                    {language !== 'gu' ? (
                      <button
                        type="button"
                        className="px-2 py-1 rounded border text-xs bg-white hover:bg-slate-50"
                        onClick={() => createLinkedTranslation('gu')}
                      >Create Gujarati version</button>
                    ) : null}
                  </div>
                ) : null}
              </div>
              <div>
                <label className="block text-xs font-medium">Status</label>
                <select
                  value={status}
                  onChange={e=> {
                    setStatus(e.target.value as any);
                    setStatusExplicitlyChanged(true);
                  }}
                  disabled={userRole==='writer'}
                  className="w-full border px-2 py-2 rounded"
                >
                  <option value='draft'>Draft</option>
                  <option value='scheduled'>Scheduled</option>
                  {(userRole==='admin'||userRole==='founder') && <option value='published'>Published</option>}
                </select>
              </div>
              <div className="rounded-lg border border-slate-200 bg-slate-50 p-3">
                <div className="flex items-start justify-between gap-3">
                  <div>
                    <div className="text-xs font-semibold text-slate-900">Sponsored Article</div>
                    <div className="mt-1 text-[11px] text-slate-600">Use this only for paid article pages so normal editorial stories stay separate and clean.</div>
                  </div>
                  <label className="flex items-center gap-2 text-xs font-medium text-slate-700">
                    <input
                      type="checkbox"
                      checked={isSponsoredArticle}
                      onChange={(e) => setIsSponsoredArticle(e.target.checked)}
                    />
                    Mark as Sponsored Article
                  </label>
                </div>

                {isSponsoredArticle ? (
                  <div className="mt-3 space-y-3">
                    <div>
                      <label className="block text-xs font-medium">Sponsor / Brand Name</label>
                      <input
                        value={sponsorBrandName}
                        onChange={(e) => setSponsorBrandName(e.target.value)}
                        className="w-full border px-2 py-2 rounded text-sm"
                        placeholder="Enter sponsor or brand name"
                      />
                    </div>
                    <div>
                      <label className="block text-xs font-medium">Sponsor Disclosure</label>
                      <input
                        value={sponsorDisclosure}
                        onChange={(e) => setSponsorDisclosure(e.target.value)}
                        className="w-full border px-2 py-2 rounded text-sm"
                        placeholder="Example: Sponsored by Brand Name"
                      />
                    </div>
                    <div className="grid grid-cols-1 gap-3">
                      <div>
                        <label className="block text-xs font-medium">CTA Text</label>
                        <input
                          value={sponsorCtaText}
                          onChange={(e) => setSponsorCtaText(e.target.value)}
                          className="w-full border px-2 py-2 rounded text-sm"
                          placeholder="Example: Learn More"
                        />
                      </div>
                      <div>
                        <label className="block text-xs font-medium">CTA URL</label>
                        <input
                          value={sponsorCtaUrl}
                          onChange={(e) => setSponsorCtaUrl(e.target.value)}
                          className="w-full border px-2 py-2 rounded text-sm"
                          placeholder="https://..."
                        />
                      </div>
                    </div>
                    <div className="text-[11px] text-slate-600">
                      These fields control the Sponsored Article page CTA directly. If you leave them blank, the public page only falls back to a linked Sponsored Feature CTA when a real combo link exists.
                    </div>
                    <div className="text-[11px] text-slate-600">
                      When Mark as Sponsored Article is on, this article saves and publishes as a Sponsored Article without changing the normal Add Article flow.
                    </div>
                  </div>
                ) : null}
              </div>
              {status === 'scheduled' && (
                <div>
                  <label className="block text-xs font-medium">Schedule (UTC)</label>
                  <input type="datetime-local" value={scheduledAt} onChange={e=> setScheduledAt(e.target.value)} className="w-full border px-2 py-2 rounded" />
                </div>
              )}
              <div>
                <label className="block text-xs font-medium mb-1">Tags</label>
                <TagInput value={tags} onChange={setTagsSafe} />
              </div>

              {/* Cover Image (Upload-only) */}
              <div className="pt-3 border-t border-slate-200">
                <CoverImageUpload
                  url={coverImageUrl}
                  file={coverImageFile}
                  disabled={!coverUploadEnabled || mediaStatusQuery.isLoading}
                  disabledText={coverUploadStatusText}
                  disabledDetail={coverUploadStatusDetail}
                  onChangeFile={(f) => {
                    setCoverUploadOk(false);
                    setCoverUploadError(null);
                    setCoverImageFile(f);
                    if (f) void uploadSelectedCover(f);
                  }}
                  onRemove={() => {
                    setCoverImageFile(null);
                    setCoverImage(null);
                    setCoverUploadOk(false);
                    setCoverUploadError(null);
                  }}
                  onChooseFromLibrary={() => setCoverMediaLibraryOpen(true)}
                />
                {isUploadingCover && <div className="mt-1 text-[11px] text-slate-500">Uploading…</div>}
                {!isUploadingCover && coverUploadOk && coverImageUrl ? (
                  <div className="mt-1 text-[11px] text-slate-600">Uploaded</div>
                ) : null}
                {!isUploadingCover && coverUploadError ? (
                  <div className="mt-1 text-[11px] text-red-600">{coverUploadError}</div>
                ) : null}
              </div>

              {(userRole==='founder') && (
                <div className="pt-2 border-t border-slate-200">
                  <div className="text-sm font-semibold mb-2">Founder Override</div>
                  <label className="flex items-center gap-2 text-xs">
                    <input type="checkbox" checked={founderOverride} onChange={e=> setFounderOverride(e.target.checked)} /> Enable Force Publish
                  </label>
                  {founderOverride && <div className="text-xs text-red-600 mt-1">Publishing will ignore PTI & language issues.</div>}
                </div>
              )}
            </div>
          </div>

          <div className="card p-4">
            <div className="flex items-center justify-between gap-3 mb-3">
              <div className="text-sm font-semibold">Quality Tools</div>
              <button
                type="button"
                className="text-xs text-slate-600 hover:text-slate-900 underline"
                onClick={() => setQualityToolsCollapsed((v) => !v)}
              >
                {qualityToolsCollapsed ? 'Show' : 'Minimize'}
              </button>
            </div>
            {!qualityToolsCollapsed && <Accordion items={accordionItems} />}
          </div>
        </aside>
      </div>

      <PreviewModal
        open={previewOpen}
        onClose={() => setPreviewOpen(false)}
        article={{
          title,
          slug,
          summary,
          content,
          coverImageUrl: coverImageUrl || undefined,
          category,
          language,
          status,
          scheduledAt,
          tags,
        }}
      />

      <MediaLibrarySelector
        open={coverMediaLibraryOpen}
        mode="image"
        title="Choose Cover Image"
        actionLabel="Use as Cover"
        onClose={() => setCoverMediaLibraryOpen(false)}
        onSelect={chooseCoverFromMediaLibrary}
      />

      {publishSuccess && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 p-4">
          <div className="w-full max-w-md rounded-lg border border-slate-200 bg-white p-4 shadow-lg">
            <div className="text-sm font-semibold text-slate-900">
              {publishSuccess.syncResults ? 'Published and synced' : 'Published ✅ (Translations pending)'}
            </div>
            <div className="mt-1 text-xs text-slate-600">
              {publishSuccess.id ? `Article ID: ${publishSuccess.id}` : 'Article published'}
            </div>
            {publishSuccess.syncResults ? (
              <div className="mt-3 rounded border border-slate-200 bg-slate-50 p-3">
                <div className="text-xs font-semibold text-slate-900">Sync Results</div>
                <div className="mt-2 space-y-1 text-[11px] text-slate-700">
                  {(['en', 'hi', 'gu'] as const).map((code) => (
                    <div key={`publish-sync-${code}`}>{publishSuccess.syncResults?.[code] || `${code.toUpperCase()} needs refresh`}</div>
                  ))}
                </div>
              </div>
            ) : null}
            <div className="mt-4 flex items-center justify-end gap-2">
              <button
                type="button"
                className="btn-secondary"
                onClick={() => {
                  const url = publishSuccess.viewUrl;
                  setPublishSuccess(null);
                  if (url) window.open(url, '_blank', 'noreferrer');
                }}
              >
                View Live
              </button>
              <button
                type="button"
                className="btn-secondary"
                onClick={() => {
                  const id = publishSuccess.id;
                  setPublishSuccess(null);
                  const qs = new URLSearchParams();
                  qs.set('status', 'published');
                  if (id) qs.set('highlight', String(id));
                  navigate(`/admin/articles?${qs.toString()}`);
                }}
              >
                Go to Manage News
              </button>
              <button
                type="button"
                className="btn"
                onClick={() => {
                  resetToNewArticle();
                }}
              >
                New Article
              </button>
            </div>
          </div>
        </div>
      )}

      <ConfirmModal
        open={!!confirmState}
        title={confirmState?.title || ''}
        description={confirmState?.description}
        confirmLabel={confirmState?.confirmLabel}
        cancelLabel={confirmState?.cancelLabel}
        onCancel={() => setConfirmState(null)}
        onConfirm={() => confirmState?.onConfirm()}
      />

      {/* Optional helpful banner on missing backend route */}
      {mutation.isError && (mutation.error as any)?.response?.status === 404 && (
        <div className="mb-3 rounded-lg border border-amber-300 bg-amber-50 text-amber-900 px-3 py-2 text-sm">
          Backend route missing (articles). Check backend deployment.
        </div>
      )}

      {/* Sticky action bar */}
      <div className="fixed bottom-0 left-0 right-0 z-40 border-t border-slate-200 bg-white/95 backdrop-blur">
        <div className="max-w-5xl mx-auto px-4 py-3 flex items-center justify-between gap-4">
          <div className="text-sm text-slate-600 flex items-center gap-2">
            <span
              className={
                autosaveFailed
                  ? 'text-red-700 font-medium'
                  : (isDirty ? 'text-slate-700 font-medium' : 'text-green-700')
              }
            >
              {saveStatusText}
            </span>
            {autosaveFailed && (
              <button
                type="button"
                className="text-xs underline text-red-700"
                onClick={() => {
                  setAutosaveFailed(false);
                  setAutosaveError(null);
                  saveKindRef.current = 'manual';
                  saveDraft();
                }}
                title={autosaveError || undefined}
              >Retry</button>
            )}
          </div>
          <div className="flex items-center gap-2">
            {(effectiveId && translationStatus === 'failed') && (
              <button
                type="button"
                onClick={() => retryTranslationMutation.mutate()}
                className="btn-secondary"
                disabled={retryTranslationMutation.isPending || isSaving || isPublishing}
              >
                {retryTranslationMutation.isPending ? 'Retrying…' : 'Retry Translation'}
              </button>
            )}
            <button type="button" onClick={saveDraft} className="btn-secondary" disabled={isSaving || isPublishing || mutation.isPending}>Save Draft</button>
            <button
              type="button"
              onClick={() => setPreviewOpen(true)}
              className="btn-secondary"
              disabled={!previewEnabled}
              title={!previewEnabled ? 'Add Title and Content to preview' : undefined}
            >Preview</button>
            <span className="inline-flex" title={publishTooltip}>
              <button
                type="button"
                onClick={() => { void beginPublishFlow(); }}
                className="btn"
                disabled={!canPublish || isSaving || isPublishing}
              >
                {isPublishing ? 'Publishing…' : 'Publish'}
              </button>
            </span>
          </div>
        </div>
      </div>
    </form>
  );
};

import React from 'react';
import { useNavigate } from 'react-router-dom';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import {
  listArticles,
  archiveArticle,
  restoreArticle,
  deleteArticle,
  updateArticleStatus,
  scheduleArticle,
  unscheduleArticle,
  hardDeleteArticle,
  type Article,
  type ListResponse,
} from '@/lib/api/articles';
import toast from 'react-hot-toast';
import { normalizeError } from '@/lib/error';
import { useAuth } from '@/context/AuthContext';
import type { ArticleStatus } from '@/types/articles';
import { ScheduleDialog } from './ScheduleDialog';
import { usePublishFlag } from '@/context/PublishFlagContext';

import type { ManageNewsParams } from '@/types/api';
interface Props {
  params: ManageNewsParams;
  onSelectIds?: (ids: string[]) => void;
  onPageChange?: (page: number) => void;
  highlightId?: string;
  quickView?: 'all' | 'breaking' | 'regional';
  onQuickViewCounts?: (counts: { all: number; breaking: number; regional: number }) => void;
}

export const ArticleTable: React.FC<Props> = ({ params, onSelectIds, onPageChange, highlightId, quickView = 'all', onQuickViewCounts }) => {
  const navigate = useNavigate();
  const qc = useQueryClient();
  const { user } = useAuth();
  const role = user?.role || 'editor';
  // Call all hooks unconditionally at the top (before any early returns)
  const { publishEnabled } = usePublishFlag();
  const canArchive = role === 'admin' || role === 'founder' || role === 'editor';
  const canDelete = role === 'admin' || role === 'founder';
  const { data, isLoading, error } = useQuery<ListResponse>({ queryKey: ['articles', params], queryFn: () => listArticles(params) });
  // Optimistic mutations
  const mutateArchive = useMutation({
    mutationFn: archiveArticle,
    onMutate: async (id: string) => {
      await qc.cancelQueries({ queryKey: ['articles'] });
      const prev = qc.getQueryData<ListResponse>(['articles', params]);
      if (prev?.rows) {
        qc.setQueryData(['articles', params], {
          ...prev,
          rows: prev.rows.map((a: Article)=> a._id===id? { ...a, status:'archived' }: a)
        });
      }
      return { prev };
    },
    onError: (_err, _id, ctx) => { if (ctx?.prev) qc.setQueryData(['articles', params], ctx.prev); toast.error('Archive failed'); },
    onSuccess: () => { toast.success('Archived'); },
    onSettled: () => { qc.invalidateQueries({ queryKey:['articles']}); }
  });
  const mutateRestore = useMutation({
    mutationFn: restoreArticle,
    onMutate: async (id: string) => {
      await qc.cancelQueries({ queryKey: ['articles'] });
      const prev = qc.getQueryData<ListResponse>(['articles', params]);
      if (prev?.rows) {
        qc.setQueryData(['articles', params], {
          ...prev,
          rows: prev.rows.map((a: Article)=> a._id===id? { ...a, status:'draft' }: a)
        });
      }
      return { prev };
    },
    onError: (_err, _id, ctx) => { if (ctx?.prev) qc.setQueryData(['articles', params], ctx.prev); toast.error('Restore failed'); },
    onSuccess: () => { toast.success('Restored'); },
    onSettled: () => { qc.invalidateQueries({ queryKey:['articles']}); }
  });
  const mutateDelete = useMutation({
    mutationFn: deleteArticle,
    onMutate: async (id: string) => {
      await qc.cancelQueries({ queryKey: ['articles'] });
      const prev = qc.getQueryData<ListResponse>(['articles', params]);
      if (prev?.rows) {
        // In All view, drop the row immediately; otherwise mark as deleted
        const inAllView = (params.status ?? 'all') === 'all';
        qc.setQueryData(['articles', params], {
          ...prev,
          rows: inAllView
            ? prev.rows.filter((a: Article) => a._id !== id)
            : prev.rows.map((a: Article)=> a._id===id? { ...a, status:'deleted' }: a),
          total: Math.max(0, (prev.total || 1) - (inAllView ? 1 : 0)),
        });
      }
      return { prev };
    },
    onError: (_err, _id, ctx) => { if (ctx?.prev) qc.setQueryData(['articles', params], ctx.prev); toast.error('Delete failed'); },
    onSuccess: () => { toast.success('Deleted'); },
    onSettled: () => { qc.invalidateQueries({ queryKey:['articles']}); }
  });
  const [selected, setSelected] = React.useState<string[]>([]);
  
  // Actions helper
  type ArticleAction =
    | 'edit'
    | 'publishNow'
    | 'schedule'
    | 'unschedule'
    | 'unpublish'
    | 'archive'
    | 'restore'
    | 'deleteSoft'
    | 'deleteHard';

  function getAvailableActions(status: ArticleStatus): ArticleAction[] {
    switch (status) {
      case 'draft':
        return ['edit', 'publishNow', 'schedule', 'archive', 'deleteSoft'];
      case 'scheduled':
        return ['edit', 'unschedule', 'archive', 'deleteSoft'];
      case 'published':
        return ['edit', 'unpublish', 'archive', 'deleteSoft'];
      case 'archived':
        return ['edit', 'restore', 'deleteSoft'];
      case 'deleted':
        return ['restore', 'deleteHard'];
      default:
        return ['edit'];
    }
  }

  // Mutations for status transitions
  const mutatePublish = useMutation({
    mutationFn: (id: string) => updateArticleStatus(id, 'published'),
    onSuccess: () => { toast.success('Published'); },
    onSettled: () => { qc.invalidateQueries({ queryKey: ['articles'] }); }
  });
  const mutateUnpublish = useMutation({
    mutationFn: (id: string) => updateArticleStatus(id, 'draft'),
    onSuccess: () => { toast.success('Unpublished'); },
    onError: (err: any) => {
      const n = normalizeError(err, 'Unpublish failed');
      toast.error(n.message || 'Unpublish failed');
    },
    onSettled: () => { qc.invalidateQueries({ queryKey: ['articles'] }); }
  });
  const mutateSchedule = useMutation({
    mutationFn: ({ id, at }: { id: string; at: string }) => scheduleArticle(id, at),
    onSuccess: (_data, vars) => { toast.success(`Scheduled for local time ${new Date(vars.at).toLocaleString()}`); },
    onSettled: () => { qc.invalidateQueries({ queryKey: ['articles'] }); }
  });
  const mutateUnschedule = useMutation({
    mutationFn: (id: string) => unscheduleArticle(id),
    onSuccess: () => { toast.success('Unscheduled'); },
    onSettled: () => { qc.invalidateQueries({ queryKey: ['articles'] }); }
  });
  const [hardDeletingId, setHardDeletingId] = React.useState<string | null>(null);
  const mutateDeleteHard = useMutation({
    mutationFn: (id: string) => hardDeleteArticle(id),
    onMutate: async (id: string) => {
      setHardDeletingId(id);
      // Optimistic removal from current page
      await qc.cancelQueries({ queryKey: ['articles'] });
      const prev = qc.getQueryData<ListResponse>(['articles', params]);
      const rows: Article[] | null = Array.isArray((prev as any)?.rows)
        ? (prev as any).rows
        : (Array.isArray((prev as any)?.data) ? (prev as any).data : null);
      if (prev && rows) {
        const nextRows = rows.filter((a: Article) => a._id !== id);
        const removed = rows.length - nextRows.length;
        if (removed > 0) {
          const next: any = { ...(prev as any) };
          if (Array.isArray((prev as any).rows)) next.rows = nextRows;
          if (Array.isArray((prev as any).data)) next.data = nextRows;
          if (typeof (prev as any).total === 'number') next.total = Math.max(0, (prev as any).total - removed);
          qc.setQueryData(['articles', params], next);
        }
      }
      return { prev };
    },
    onError: (_err, _id, ctx) => {
      if (ctx?.prev) qc.setQueryData(['articles', params], ctx.prev);
      toast.error('Hard delete failed');
    },
    onSuccess: () => { toast.success('Deleted forever'); },
    onSettled: () => { setHardDeletingId(null); qc.invalidateQueries({ queryKey: ['articles'] }); }
  });
  // Scheduling dialog state
  const [scheduleOpen, setScheduleOpen] = React.useState(false);
  const [scheduleTarget, setScheduleTarget] = React.useState<Article | null>(null);

  // derive table rows and total from the query result (safe during loading)
  const rawRows: Article[] = (data as any)?.rows ?? (data as any)?.data ?? [];
  const total: number = (data as any)?.total ?? rawRows.length;

  const isSeededSample = React.useCallback((a: Article) => {
    const title = String(a?.title || '').toLowerCase();
    const authorName = String(a?.author?.name || '').toLowerCase();
    const tags = Array.isArray((a as any)?.tags)
      ? ((a as any).tags as any[]).map((t) => String(t || '').toLowerCase())
      : [];

    // Backend seed artifacts we never want to show in the admin list.
    if (authorName === 'seeder') return true;
    if (title.startsWith('sample article')) return true;
    if (tags.includes('demo') && tags.includes('seed')) return true;
    return false;
  }, []);

  // UX requirement: Deleted items must NOT appear in the "All" tab.
  // They should only appear when status === 'deleted'.
  const baseRows: Article[] = React.useMemo(() => {
    const view = (params.status ?? 'all') as any;
    const cleaned = rawRows.filter((r) => !isSeededSample(r));
    if (view === 'all') return cleaned.filter((r) => (r.status ?? 'draft') !== 'deleted');
    return cleaned;
  }, [rawRows, params.status, isSeededSample]);

  function norm(s: any): string {
    return String(s || '').trim().toLowerCase();
  }

  function getTags(a: Article): string[] {
    const t = (a as any)?.tags;
    return Array.isArray(t) ? t.map((x) => String(x || '').trim()).filter(Boolean) : [];
  }

  function isBreakingStory(a: Article): boolean {
    const cat = norm((a as any)?.category);
    const tags = getTags(a).map((t) => norm(t));
    return cat === 'breaking' || tags.includes('breaking');
  }

  function isRegionalStory(a: Article): boolean {
    const tags = getTags(a).map((t) => norm(t));
    return (
      tags.includes('state:gujarat')
      || tags.includes('gujarat')
      || tags.some((t) => t.startsWith('district:'))
      || tags.some((t) => t.startsWith('city:'))
    );
  }

  const quickCounts = React.useMemo(() => {
    const all = baseRows.length;
    const breaking = baseRows.filter(isBreakingStory).length;
    const regional = baseRows.filter(isRegionalStory).length;
    return { all, breaking, regional };
  }, [baseRows]);

  React.useEffect(() => {
    onQuickViewCounts?.(quickCounts);
  }, [onQuickViewCounts, quickCounts]);

  const rows: Article[] = React.useMemo(() => {
    if (quickView === 'breaking') return baseRows.filter(isBreakingStory);
    if (quickView === 'regional') return baseRows.filter(isRegionalStory);
    return baseRows;
  }, [baseRows, quickView]);

  const [didScrollHighlight, setDidScrollHighlight] = React.useState(false);
  React.useEffect(() => {
    // allow new highlight ids to re-trigger scroll
    setDidScrollHighlight(false);
  }, [highlightId]);

  React.useEffect(() => {
    if (!highlightId) return;
    if (didScrollHighlight) return;
    const existsOnPage = (rows as Article[]).some((r) => r._id === highlightId);
    if (!existsOnPage) return;
    // small delay so table renders
    window.setTimeout(() => {
      const el = document.getElementById(`article-row-${highlightId}`);
      el?.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }, 50);
    setDidScrollHighlight(true);
  }, [didScrollHighlight, highlightId, rows]);

  React.useEffect(()=>{ onSelectIds?.(selected); },[selected]);
  if (isLoading) return <div className="animate-pulse text-slate-500">Loading articles…</div>;
  if (error) {
    const n = normalizeError(error, 'Error loading articles');
    return <div className="text-red-600">{n.message}</div>;
  }

  if (!rows.length && quickView === 'breaking') {
    return (
      <div className="rounded border bg-white p-4 text-sm text-slate-700">
        <div className="font-semibold">No breaking stories found.</div>
        <div className="mt-1 text-xs text-slate-600">Create one from Add News → Mark as Breaking.</div>
      </div>
    );
  }

  const page = data?.page || 1;
  const pages = data?.pages || 1;
  const canPrev = page > 1;
  const canNext = page < pages;
  return (
    <>
    <table className="w-full text-sm border">
      <thead className="sticky top-0 bg-slate-100">
        <tr className="text-left">
          <th className="p-2"><input type="checkbox" onChange={e=> setSelected(e.target.checked? rows.map((r:Article)=> r._id): [])} /></th>
          <th className="p-2">Title</th>
          <th className="p-2">Status</th>
          <th className="p-2">Author</th>
          <th className="p-2">PTI</th>
          <th className="p-2">Trust</th>
          <th className="p-2">Created</th>
          <th className="p-2">Actions</th>
        </tr>
      </thead>
      <tbody>
        {rows.map((r: Article)=> {
          const statusColors: Record<'draft'|'scheduled'|'published'|'archived'|'deleted', string> = {
            draft: 'bg-gray-500', scheduled: 'bg-amber-600', published: 'bg-green-600', archived: 'bg-slate-600', deleted: 'bg-red-700'
          };
          const st = (r.status ?? 'draft') as ArticleStatus;
          const badge = statusColors[st] || 'bg-gray-500';

          const ptiColors: Record<'compliant'|'pending'|'rejected', string> = { compliant: 'bg-green-600', pending: 'bg-amber-600', rejected: 'bg-red-600' };
          const pti = (r.ptiCompliance ?? 'pending') as 'compliant'|'pending'|'rejected';
          const ptiBadge = ptiColors[pti];

          const isHighlighted = !!highlightId && r._id === highlightId;
          return (
            <tr
              key={r._id}
              id={`article-row-${r._id}`}
              className={`border-t hover:bg-slate-50 ${isHighlighted ? 'bg-amber-50' : ''}`}
            >
              <td className="p-2"><input type="checkbox" checked={selected.includes(r._id)} onChange={()=> setSelected(s=> s.includes(r._id)? s.filter(x=>x!==r._id): [...s, r._id])} /></td>
              <td className="p-2">
                <div className="font-medium flex items-center gap-2">
                  <span>{r.title}</span>
                  <span className="px-1.5 py-0.5 rounded bg-indigo-600 text-white text-[10px]">{r.language?.toUpperCase()}</span>
                  <span className="px-1 py-0.5 rounded bg-sky-700 text-white text-[10px]">{r.category}</span>
                  {quickView === 'breaking' && isBreakingStory(r) && (
                    <span className="px-1.5 py-0.5 rounded bg-amber-500 text-white text-[10px]">⚡ Breaking</span>
                  )}
                  {quickView === 'regional' && (() => {
                    const tags = getTags(r).map((t) => norm(t));
                    const hasLoc = tags.some((t) => t.startsWith('district:')) || tags.some((t) => t.startsWith('city:'));
                    if (!hasLoc) return null;
                    return <span className="px-1.5 py-0.5 rounded bg-slate-700 text-white text-[10px]">📍 district/city</span>;
                  })()}
                </div>
              </td>
              <td className="p-2"><span className={`px-2 py-0.5 rounded text-white ${badge}`}>{st}</span></td>
              <td className="p-2">{r.author?.name || '—'}</td>
              <td className="p-2"><span className={`px-2 py-0.5 rounded text-white ${ptiBadge}`}>{r.ptiCompliance}</span></td>
              <td className="p-2">{r.trustScore ?? 0}</td>
              <td className="p-2">{(() => { const t = r.createdAt && !Number.isNaN(Date.parse(r.createdAt)) ? new Date(r.createdAt).toLocaleString() : '—'; return t; })()}</td>
              <td className="p-2 space-x-2">
                {getAvailableActions((r.status || 'draft') as ArticleStatus).includes('edit') && (
                  <button onClick={()=> navigate(`/admin/articles/${r._id}/edit`)} className="text-blue-600 hover:underline">Edit</button>
                )}
                {getAvailableActions(r.status as ArticleStatus).includes('publishNow') && (
                  publishEnabled ? (
                    <button onClick={()=> mutatePublish.mutate(r._id)} className="text-green-700 hover:underline">Publish</button>
                  ) : (
                    <span className="text-slate-400 cursor-not-allowed">Publish (disabled)</span>
                  )
                )}
                {getAvailableActions(r.status as ArticleStatus).includes('schedule') && (
                  publishEnabled ? (
                    <button
                      onClick={()=> {
                        setScheduleTarget(r);
                        setScheduleOpen(true);
                      }}
                      className="text-amber-700 hover:underline"
                    >Schedule</button>
                  ) : (
                    <span className="text-slate-400 cursor-not-allowed">Schedule (disabled)</span>
                  )
                )}
                {getAvailableActions(r.status as ArticleStatus).includes('unschedule') && (
                  <button onClick={()=> mutateUnschedule.mutate(r._id)} className="text-amber-700 hover:underline">Unschedule</button>
                )}
                {getAvailableActions(r.status as ArticleStatus).includes('unpublish') && (
                  <button onClick={()=> mutateUnpublish.mutate(r._id)} className="text-slate-700 hover:underline">Unpublish</button>
                )}
                {getAvailableActions(r.status as ArticleStatus).includes('archive') && canArchive && (
                  <button onClick={()=> mutateArchive.mutate(r._id)} className="text-slate-600 hover:underline">Archive</button>
                )}
                {getAvailableActions(r.status as ArticleStatus).includes('restore') && (
                  <button onClick={()=> mutateRestore.mutate(r._id)} className="text-green-600 hover:underline">Restore</button>
                )}
                {getAvailableActions(r.status as ArticleStatus).includes('deleteSoft') && canDelete && (
                  <button onClick={()=> mutateDelete.mutate(r._id)} className="text-red-600 hover:underline">Delete</button>
                )}
                {getAvailableActions(r.status as ArticleStatus).includes('deleteHard') && canDelete && (
                  <button
                    disabled={hardDeletingId === r._id}
                    onClick={()=> {
                      const ok = confirm('Are you sure? This will permanently delete this article. This action cannot be undone.');
                      if (ok) mutateDeleteHard.mutate(r._id);
                    }}
                    className={`hover:underline ${hardDeletingId === r._id ? 'text-slate-400 cursor-not-allowed' : 'text-red-700'}`}
                  >{hardDeletingId === r._id ? 'Deleting…' : 'Delete forever'}</button>
                )}
              </td>
            </tr>
          );
        })}
      </tbody>
  </table>
    <div className="flex items-center justify-between mt-3 text-sm">
      <div>Showing page {page} of {pages} • {total} total</div>
      <div className="flex items-center gap-2">
  <button disabled={!canPrev} onClick={()=> onPageChange?.(page - 1)} className={`px-2 py-1 rounded border ${canPrev? '':'opacity-50'}`}>Prev</button>
  <button disabled={!canNext} onClick={()=> onPageChange?.(page + 1)} className={`px-2 py-1 rounded border ${canNext? '':'opacity-50'}`}>Next</button>
      </div>
      {selected.length>0 && (
        <div className="flex items-center gap-2">
          {canArchive && <button onClick={()=> { if (confirm(`Archive ${selected.length} items?`)) selected.forEach(id=> mutateArchive.mutate(id)); }} className="px-2 py-1 rounded border">Archive</button>}
          {canArchive && <button onClick={()=> { if (confirm(`Restore ${selected.length} items?`)) selected.forEach(id=> mutateRestore.mutate(id)); }} className="px-2 py-1 rounded border">Restore</button>}
          {canDelete && <button onClick={()=> { if (confirm(`Delete ${selected.length} items?`)) selected.forEach(id=> { mutateDelete.mutate(id); toast((t)=> (<span>Deleted. <button className='underline' onClick={()=> { mutateRestore.mutate(id); toast.dismiss(t.id); }}>Undo</button></span>), { duration: 4000 }); }); }} className="px-2 py-1 rounded border text-red-600">Delete</button>}
        </div>
      )}
    </div>
    {/* Schedule Dialog */}
    <ScheduleDialog
      isOpen={scheduleOpen}
      initialDateTime={(() => {
        if (!scheduleTarget) return undefined;
        const base = scheduleTarget.publishAt || scheduleTarget.scheduledAt || null;
        return base;
      })()}
      onCancel={() => { setScheduleOpen(false); setScheduleTarget(null); }}
      onConfirm={(localValue) => {
        if (!scheduleTarget) return;
        // localValue format: YYYY-MM-DDTHH:mm (local). new Date parses as local time.
        const iso = new Date(localValue).toISOString();
        if (!iso || Number.isNaN(Date.parse(iso))) { toast.error('Invalid date'); return; }
        mutateSchedule.mutate({ id: scheduleTarget._id, at: iso });
        setScheduleOpen(false);
        setScheduleTarget(null);
      }}
    />
    </>
  );
};

import React from 'react';
import { useNavigate } from 'react-router-dom';
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import toast from 'react-hot-toast';

import type { ManageNewsParams } from '@/types/api';
import type { ArticleStatus } from '@/types/articles';
import {
  listArticles,
  archiveArticle,
  restoreArticle,
  deleteArticle,
  updateArticleStatus,
  scheduleArticle,
  unscheduleArticle,
  hardDeleteArticle,
  bulkHardDeleteArticles,
  type Article,
  type ListResponse,
} from '@/lib/api/articles';
import { normalizeError } from '@/lib/error';
import { useAuth } from '@/context/AuthContext';
import { usePublishFlag } from '@/context/PublishFlagContext';
import { ScheduleDialog } from './ScheduleDialog';
import type { QuickViewCounts, QuickViewKey } from './QuickViewsBar';
import { listAdminAnalyticsArticles, type ArticlesAnalyticsRow } from '@/lib/api/adminAnalytics';
import { formatDurationShort, formatNumberCompact, formatPercent } from '@/lib/formatDuration';

function norm(s: any): string {
  return String(s || '').trim().toLowerCase();
}

function getTags(a: Article): string[] {
  const t = (a as any)?.tags;
  return Array.isArray(t) ? t.map((x) => String(x || '').trim()).filter(Boolean) : [];
}

function isBreakingStory(a: Article): boolean {
  const cat = norm((a as any)?.category);
  const tags = getTags(a).map((t) => norm(t));
  return cat === 'breaking' || tags.includes('breaking');
}

function isGujaratRegional(a: Article): boolean {
  const tags = getTags(a).map((t) => norm(t));
  return (
    tags.includes('state:gujarat')
    || tags.includes('gujarat')
    || tags.some((t) => t.startsWith('district:'))
    || tags.some((t) => t.startsWith('city:'))
  );
}

function needsPtiReview(a: Article): boolean {
  const v = norm((a as any)?.ptiCompliance);
  if (!v) return false;
  return v !== 'compliant';
}

function isFlagged(a: Article): boolean {
  const flags = (a as any)?.flags;
  if (Array.isArray(flags) && flags.length > 0) return true;
  const tags = getTags(a).map((t) => norm(t));
  if (tags.includes('flagged')) return true;
  const workflowLocked = !!(a as any)?.workflow?.locked;
  return workflowLocked;
}

function isAiVerified(a: Article): boolean {
  return !!((a as any)?.aiVerified || (a as any)?.ai_verified || (a as any)?.ai_verified === true || (a as any)?.aiVerifiedAt);
}

function getLocationTags(a: Article): string[] {
  const tags = getTags(a).map((t) => norm(t));
  return tags.filter((t) => t.startsWith('district:') || t.startsWith('city:'));
}

function formatUpdatedAt(a: Article): string {
  const raw = (a as any)?.updatedAt || (a as any)?.createdAt;
  if (!raw) return '—';
  const ts = Date.parse(String(raw));
  if (Number.isNaN(ts)) return '—';
  return new Date(ts).toLocaleString();
}

function formatLangTag(code: any): string {
  const c = String(code || '').trim().toLowerCase();
  if (!c) return '';
  if (c === 'en') return 'EN';
  if (c === 'hi') return 'HI';
  if (c === 'gu') return 'GU';
  return c.slice(0, 4).toUpperCase();
}

function getArticleLanguageBadge(a: Article): string {
  const langs = new Set<string>();
  const primary = String((a as any)?.lang ?? (a as any)?.language ?? '').trim().toLowerCase();
  if (primary) langs.add(primary);

  const translations = (a as any)?.translations;
  if (translations && typeof translations === 'object') {
    for (const k of Object.keys(translations)) {
      const code = String(k || '').trim().toLowerCase();
      if (code) langs.add(code);
    }
  }

  const ordered = ['en', 'hi', 'gu'];
  const picked = ordered.filter((x) => langs.has(x));
  if (picked.length >= 2) return picked.map(formatLangTag).join('+');

  const only = picked[0] || primary;
  return formatLangTag(only);
}

function isAdminArticleDebugEnabled(): boolean {
  try {
    const w: any = window as any;
    if (w && (w.__np_debug_article_editor || w.__np_debug_article_requests)) return true;
  } catch {}
  try {
    return localStorage.getItem('np_debug_article_editor') === '1'
      || localStorage.getItem('np_debug_article_requests') === '1';
  } catch {
    return false;
  }
}

function logNewsTableAction(label: string, payload: Record<string, any>): void {
  if (!isAdminArticleDebugEnabled()) return;
  console.log(`[NewsTable] ${label}`, payload);
}

function getAuthorName(a: Article): string {
  const authorRaw = (a as any)?.author;

  // author can be a string in some environments
  if (typeof authorRaw === 'string' && authorRaw.trim()) return authorRaw.trim();

  // author can be an array of strings/objects
  if (Array.isArray(authorRaw) && authorRaw.length > 0) {
    const first = authorRaw[0] as any;
    if (typeof first === 'string' && first.trim()) return first.trim();
    const n1 = first?.name || first?.fullName || first?.displayName || first?.username;
    if (n1 && String(n1).trim()) return String(n1).trim();
  }

  // author can be an object with different keys
  const direct = (authorRaw as any)?.name
    || (authorRaw as any)?.fullName
    || (authorRaw as any)?.displayName
    || (authorRaw as any)?.username;
  if (direct && String(direct).trim()) return String(direct).trim();

  // Common alternates
  const alt = (a as any)?.authorName
    || (a as any)?.by
    || (a as any)?.byline
    || (a as any)?.reporter
    || (a as any)?.writer
    || (a as any)?.createdByName
    || (a as any)?.created_by_name;
  if (alt && String(alt).trim()) return String(alt).trim();

  // Nested creators / users
  const createdBy = (a as any)?.createdBy?.name
    || (a as any)?.createdBy?.fullName
    || (a as any)?.created_by?.name
    || (a as any)?.created_by?.fullName
    || (a as any)?.user?.name
    || (a as any)?.user?.fullName;
  if (createdBy && String(createdBy).trim()) return String(createdBy).trim();

  return '';
}

interface Props {
  params: ManageNewsParams;
  search: string;
  quickView: QuickViewKey;
  onCounts: (counts: QuickViewCounts) => void;
  onSelectIds?: (ids: string[]) => void;
  onPageChange?: (page: number) => void;
  highlightId?: string;
  stickyTopOffsetPx?: number;
}

export function NewsTable({ params, search, quickView, onCounts, onSelectIds, onPageChange, highlightId, stickyTopOffsetPx = 0 }: Props) {
  const navigate = useNavigate();
  const qc = useQueryClient();
  const { user } = useAuth();
  const role = user?.role || 'editor';
  const { publishEnabled } = usePublishFlag();

  const [showAnalyticsCols, setShowAnalyticsCols] = React.useState<boolean>(() => {
    try { return localStorage.getItem('np_admin_articles_show_analytics') === 'true'; } catch { return false; }
  });
  const [analyticsRange, setAnalyticsRange] = React.useState<'24h' | '7d' | '30d'>(() => {
    try {
      const raw = localStorage.getItem('np_admin_articles_analytics_range');
      if (raw === '24h' || raw === '7d' || raw === '30d') return raw;
    } catch {}
    return '30d';
  });

  React.useEffect(() => {
    try { localStorage.setItem('np_admin_articles_show_analytics', String(showAnalyticsCols)); } catch {}
  }, [showAnalyticsCols]);
  React.useEffect(() => {
    try { localStorage.setItem('np_admin_articles_analytics_range', analyticsRange); } catch {}
  }, [analyticsRange]);

  const canArchive = role === 'admin' || role === 'founder' || role === 'editor';
  const canDelete = role === 'admin' || role === 'founder';

  // Build a stable fetch params object so react-query doesn't refetch on every render
  // when the parent passes a freshly-created `params` object.
  // Also ensure backend search is driven by `search`.
  const fetchParams = React.useMemo<ManageNewsParams>(() => {
    const q = String(search || '').trim();
    return {
      status: params.status,
      category: params.category,
      language: params.language,
      from: params.from,
      to: params.to,
      q: q ? q : undefined,
      page: params.page,
      limit: params.limit,
      sort: params.sort,
    };
  }, [
    params.status,
    params.category,
    params.language,
    params.from,
    params.to,
    params.page,
    params.limit,
    params.sort,
    search,
  ]);

  const { data, isLoading, error } = useQuery<ListResponse>({
    queryKey: [
      'articles',
      fetchParams.page ?? 1,
      fetchParams.limit ?? 20,
      fetchParams.sort ?? '-updatedAt',
      fetchParams.status ?? 'all',
      fetchParams.category ?? '',
      fetchParams.language ?? '',
      fetchParams.from ?? '',
      fetchParams.to ?? '',
      fetchParams.q ?? '',
    ],
    queryFn: () => listArticles(fetchParams),
  });

  const rawRows: Article[] = (data as any)?.rows ?? (data as any)?.data ?? [];
  const total: number = (data as any)?.total ?? rawRows.length;
  const page = (data as any)?.page || 1;
  const pages = (data as any)?.pages || 1;

  // Mutations
  const mutateArchive = useMutation({
    mutationFn: archiveArticle,
    onSuccess: () => toast.success('Archived'),
    onError: (err: any) => toast.error(normalizeError(err, 'Archive failed').message),
    onSettled: () => qc.invalidateQueries({ queryKey: ['articles'] }),
  });
  const mutateRestore = useMutation({
    mutationFn: restoreArticle,
    onSuccess: () => toast.success('Restored'),
    onError: (err: any) => toast.error(normalizeError(err, 'Restore failed').message),
    onSettled: () => qc.invalidateQueries({ queryKey: ['articles'] }),
  });
  const mutateDelete = useMutation({
    mutationFn: deleteArticle,
    onSuccess: () => toast.success('Deleted'),
    onError: (err: any) => toast.error(normalizeError(err, 'Delete failed').message),
    onSettled: () => qc.invalidateQueries({ queryKey: ['articles'] }),
  });
  const mutatePublish = useMutation({
    mutationFn: (id: string) => updateArticleStatus(id, 'published'),
    onSuccess: () => toast.success('Published'),
    onError: (err: any) => toast.error(normalizeError(err, 'Publish failed').message),
    onSettled: () => qc.invalidateQueries({ queryKey: ['articles'] }),
  });
  const mutateUnpublish = useMutation({
    mutationFn: (id: string) => updateArticleStatus(id, 'draft'),
    onSuccess: () => toast.success('Unpublished'),
    onError: (err: any) => toast.error(normalizeError(err, 'Unpublish failed').message),
    onSettled: () => qc.invalidateQueries({ queryKey: ['articles'] }),
  });
  const mutateUnschedule = useMutation({
    mutationFn: (id: string) => unscheduleArticle(id),
    onSuccess: () => toast.success('Unscheduled'),
    onError: (err: any) => toast.error(normalizeError(err, 'Unschedule failed').message),
    onSettled: () => qc.invalidateQueries({ queryKey: ['articles'] }),
  });
  const mutateDeleteHard = useMutation({
    mutationFn: (id: string) => hardDeleteArticle(id),
    onMutate: async (id: string) => {
      await qc.cancelQueries({ queryKey: ['articles'] });

      const prev = qc.getQueriesData<ListResponse>({ queryKey: ['articles'] });

      qc.setQueriesData({ queryKey: ['articles'] }, (old: any) => {
        if (!old) return old;
        const rows: any[] | null = Array.isArray(old?.rows)
          ? old.rows
          : (Array.isArray(old?.data) ? old.data : null);
        if (!rows) return old;

        const nextRows = rows.filter((a) => (a as any)?._id !== id);
        const removed = rows.length - nextRows.length;
        if (removed <= 0) return old;

        const next: any = { ...old };
        if (Array.isArray(old?.rows)) next.rows = nextRows;
        if (Array.isArray(old?.data)) next.data = nextRows;
        if (typeof old?.total === 'number') next.total = Math.max(0, old.total - removed);
        return next;
      });

      setSelected((cur) => cur.filter((x) => x !== id));
      return { prev };
    },
    onSuccess: () => toast.success('Deleted forever'),
    onError: (err: any, _id, ctx) => {
      if (ctx?.prev) {
        for (const [key, data] of ctx.prev as any[]) {
          qc.setQueryData(key, data);
        }
      }
      toast.error(normalizeError(err, 'Hard delete failed').message);
    },
    onSettled: () => qc.invalidateQueries({ queryKey: ['articles'] }),
  });

  const [bulkDeleting, setBulkDeleting] = React.useState(false);
  const mutateDeleteHardBulk = useMutation({
    mutationFn: (ids: string[]) => bulkHardDeleteArticles(ids),
    onMutate: async (ids: string[]) => {
      setBulkDeleting(true);
      // ensure we don't race with an inflight refetch
      await qc.cancelQueries({ queryKey: ['articles'] });
      return { ids };
    },
    onSuccess: (_data, ids: string[]) => {
      const idSet = new Set(ids);
      qc.setQueriesData({ queryKey: ['articles'] }, (old: any) => {
        if (!old) return old;
        const rows: any[] | null = Array.isArray(old?.rows)
          ? old.rows
          : (Array.isArray(old?.data) ? old.data : null);
        if (!rows) return old;

        const nextRows = rows.filter((a) => !idSet.has(String((a as any)?._id || '')));
        const removed = rows.length - nextRows.length;
        if (removed <= 0) return old;

        const next: any = { ...old };
        if (Array.isArray(old?.rows)) next.rows = nextRows;
        if (Array.isArray(old?.data)) next.data = nextRows;
        if (typeof old?.total === 'number') next.total = Math.max(0, old.total - removed);
        return next;
      });

      setSelected([]);
      toast.success(`Deleted forever (${ids.length})`);
    },
    onError: (err: any) => {
      toast.error(normalizeError(err, 'Bulk hard delete failed').message);
    },
    onSettled: () => {
      setBulkDeleting(false);
      qc.invalidateQueries({ queryKey: ['articles'] });
    },
  });

  // Schedule dialog
  const [scheduleOpen, setScheduleOpen] = React.useState(false);
  const [scheduleTarget, setScheduleTarget] = React.useState<Article | null>(null);
  const mutateSchedule = useMutation({
    mutationFn: ({ id, at }: { id: string; at: string }) => scheduleArticle(id, at),
    onSuccess: (_data, vars) => toast.success(`Scheduled for local time ${new Date(vars.at).toLocaleString()}`),
    onError: (err: any) => toast.error(normalizeError(err, 'Schedule failed').message),
    onSettled: () => qc.invalidateQueries({ queryKey: ['articles'] }),
  });

  // Selection
  const [selected, setSelected] = React.useState<string[]>([]);
  // Avoid maximum update depth errors when parent passes a non-memoized callback.
  const onSelectIdsRef = React.useRef<typeof onSelectIds>(onSelectIds);
  React.useEffect(() => { onSelectIdsRef.current = onSelectIds; }, [onSelectIds]);
  const lastSelectedKeyRef = React.useRef<string>('');
  React.useEffect(() => {
    const key = JSON.stringify(selected);
    if (key === lastSelectedKeyRef.current) return;
    lastSelectedKeyRef.current = key;
    onSelectIdsRef.current?.(selected);
  }, [selected]);

  // Client-side search + quick view filtering
  const searchKey = React.useMemo(() => norm(search), [search]);

  const isSeededSample = React.useCallback((a: Article) => {
    const title = String((a as any)?.title || '').toLowerCase();
    const authorName = String(getAuthorName(a) || '').toLowerCase();
    const tags = getTags(a).map((t) => norm(t));

    // Backend seed artifacts we never want to show in the admin list.
    if (authorName === 'seeder') return true;
    if (title.startsWith('sample article')) return true;
    if (tags.includes('demo') && tags.includes('seed')) return true;
    return false;
  }, []);

  const baseRows = React.useMemo(() => {
    // Keep parity with old behavior: hide deleted in All tab
    const view = (params.status ?? 'all') as any;
    const cleaned = rawRows.filter((r) => !isSeededSample(r));
    if (view === 'all') return cleaned.filter((r) => (r.status ?? 'draft') !== 'deleted');
    return cleaned;
  }, [rawRows, params.status, isSeededSample]);

  const searchedRows = React.useMemo(() => {
    if (!searchKey) return baseRows;
    return baseRows.filter((a) => {
      const title = norm((a as any)?.title);
      const summary = norm((a as any)?.summary);
      const content = norm((a as any)?.content);
      const category = norm((a as any)?.category);
      const tags = getTags(a).map((t) => norm(t)).join(' ');
      return (
        title.includes(searchKey)
        || summary.includes(searchKey)
        || content.includes(searchKey)
        || category.includes(searchKey)
        || tags.includes(searchKey)
      );
    });
  }, [baseRows, searchKey]);

  const counts = React.useMemo<QuickViewCounts>(() => {
    const all = searchedRows.length;
    const published = searchedRows.filter((a) => (a.status ?? 'draft') === 'published').length;
    const draft = searchedRows.filter((a) => (a.status ?? 'draft') === 'draft').length;
    const scheduled = searchedRows.filter((a) => (a.status ?? 'draft') === 'scheduled').length;
    const breaking = searchedRows.filter(isBreakingStory).length;
    const regional = searchedRows.filter(isGujaratRegional).length;
    const pti = searchedRows.filter(needsPtiReview).length;
    const flagged = searchedRows.filter(isFlagged).length;
    return {
      all,
      published,
      draft,
      scheduled,
      breaking,
      regional,
      pti,
      flagged,
    };
  }, [searchedRows]);

  // Avoid maximum update depth errors when parent passes a non-memoized callback.
  const onCountsRef = React.useRef(onCounts);
  React.useEffect(() => { onCountsRef.current = onCounts; }, [onCounts]);
  const lastCountsKeyRef = React.useRef<string>('');
  React.useEffect(() => {
    const key = JSON.stringify(counts);
    if (key === lastCountsKeyRef.current) return;
    lastCountsKeyRef.current = key;
    onCountsRef.current(counts);
  }, [counts]);

  const quickFilteredRows = React.useMemo(() => {
    switch (quickView) {
      case 'published':
        return searchedRows.filter((a) => (a.status ?? 'draft') === 'published');
      case 'draft':
        return searchedRows.filter((a) => (a.status ?? 'draft') === 'draft');
      case 'scheduled':
        return searchedRows.filter((a) => (a.status ?? 'draft') === 'scheduled');
      case 'breaking':
        return searchedRows.filter(isBreakingStory);
      case 'regional':
        return searchedRows.filter(isGujaratRegional);
      case 'pti':
        return searchedRows.filter(needsPtiReview);
      case 'flagged':
        return searchedRows.filter(isFlagged);
      case 'all':
      default:
        return searchedRows;
    }
  }, [searchedRows, quickView]);

  const sortedRows = React.useMemo(() => {
    // Lock default sorting: newest-first by updatedAt, falling back to createdAt / publishedAt.
    const getSortTs = (a: Article): number => {
      const raw = (a as any)?.updatedAt
        || (a as any)?.publishedAt
        || (a as any)?.publishAt
        || (a as any)?.createdAt
        || 0;
      const ts = Date.parse(String(raw));
      return Number.isNaN(ts) ? 0 : ts;
    };

    const arr = [...quickFilteredRows];
    arr.sort((a, b) => getSortTs(b) - getSortTs(a));
    return arr;
  }, [quickFilteredRows]);

  const analyticsQuery = useQuery({
    queryKey: ['admin', 'analytics', 'articles', 'table', analyticsRange, fetchParams],
    enabled: showAnalyticsCols,
    queryFn: async () => {
      const res = await listAdminAnalyticsArticles({
        range: analyticsRange,
        status: fetchParams.status,
        category: fetchParams.category,
        language: fetchParams.language,
        from: fetchParams.from,
        to: fetchParams.to,
        page: fetchParams.page,
        limit: fetchParams.limit,
        // tolerate search term (backend may ignore)
        ...(fetchParams.q ? { q: fetchParams.q } as any : {}),
      } as any);
      const rows = (res?.rows || res?.items || []) as ArticlesAnalyticsRow[];
      return rows;
    },
    retry: 0,
    refetchOnWindowFocus: false,
  });

  React.useEffect(() => {
    if (!analyticsQuery.isError) return;
    if (!import.meta.env.DEV) return;
    try {
      // eslint-disable-next-line no-console
      console.error('[NewsTable] analytics columns load failed', analyticsQuery.error);
    } catch {}
  }, [analyticsQuery.error, analyticsQuery.isError]);

  const analyticsById = React.useMemo(() => {
    const m = new Map<string, ArticlesAnalyticsRow>();
    for (const r of (analyticsQuery.data || [])) {
      const id = String((r as any)?.articleId || '').trim();
      if (!id) continue;
      m.set(id, r);
    }
    return m;
  }, [analyticsQuery.data]);

  const visibleIds = React.useMemo(() => sortedRows.map((a) => a._id), [sortedRows]);
  const allVisibleSelected = visibleIds.length > 0 && visibleIds.every((id) => selected.includes(id));
  const someVisibleSelected = visibleIds.some((id) => selected.includes(id));
  const selectAllRef = React.useRef<HTMLInputElement | null>(null);
  React.useEffect(() => {
    if (!selectAllRef.current) return;
    selectAllRef.current.indeterminate = !allVisibleSelected && someVisibleSelected;
  }, [allVisibleSelected, someVisibleSelected]);

  // Avoid a visible "gap" above the header when using a non-zero sticky top offset.
  // We only apply the offset after the header would collide with the sticky quick-views bar.
  const stickySentinelRef = React.useRef<HTMLDivElement | null>(null);
  const [headerPinned, setHeaderPinned] = React.useState(false);
  React.useEffect(() => {
    const update = () => {
      const el = stickySentinelRef.current;
      if (!el) return;
      const top = el.getBoundingClientRect().top;
      const nextPinned = top <= stickyTopOffsetPx;
      setHeaderPinned((p) => (p === nextPinned ? p : nextPinned));
    };

    update();
    window.addEventListener('scroll', update, { passive: true });
    window.addEventListener('resize', update);
    return () => {
      window.removeEventListener('scroll', update);
      window.removeEventListener('resize', update);
    };
  }, [stickyTopOffsetPx]);

  const effectiveStickyTop = headerPinned ? stickyTopOffsetPx : 0;

  const ActionLink = (
    {
      label,
      title,
      onClick,
      disabled,
      tone,
    }: {
      label: string;
      title?: string;
      onClick: () => void;
      disabled?: boolean;
      tone?: 'blue' | 'green' | 'amber' | 'slate' | 'red';
    },
  ) => {
    const toneClass =
      tone === 'green'
        ? 'text-green-700 hover:text-green-800'
        : tone === 'amber'
          ? 'text-amber-700 hover:text-amber-800'
          : tone === 'red'
            ? 'text-red-700 hover:text-red-800'
            : tone === 'slate'
              ? 'text-slate-700 hover:text-slate-900'
              : 'text-blue-700 hover:text-blue-800';

    return (
      <button
        type="button"
        title={title || label}
        aria-label={title || label}
        disabled={disabled}
        onClick={(e) => {
          e.stopPropagation();
          onClick();
        }}
        className={
          'text-xs font-medium underline-offset-2 hover:underline '
          + toneClass
          + (disabled ? ' opacity-50 cursor-not-allowed hover:no-underline' : '')
        }
      >
        {label}
      </button>
    );
  };

  const showSkeleton = isLoading;

  if (error) {
    const status = (error as any)?.response?.status;
    if (status === 401) {
      return (
        <div className="rounded-xl border border-slate-200 bg-white p-4 text-sm text-slate-700">
          <div className="font-semibold text-slate-900">Unauthorized</div>
          <div className="mt-1 text-xs text-slate-600">Your admin session is missing or expired. Please sign in again.</div>
          <div className="mt-3 flex items-center gap-2">
            <button
              type="button"
              onClick={() => navigate('/unauthorized', { replace: true })}
              className="rounded-md bg-slate-900 px-3 py-2 text-xs font-semibold text-white hover:bg-slate-800"
            >
              Go to sign in
            </button>
            <button
              type="button"
              onClick={() => window.location.reload()}
              className="rounded-md border border-slate-200 bg-white px-3 py-2 text-xs font-semibold text-slate-700 hover:bg-slate-50"
            >
              Reload
            </button>
          </div>
        </div>
      );
    }
    const n = normalizeError(error, 'Error loading articles');
    return <div className="text-red-600">{n.message}</div>;
  }

  const empty = !showSkeleton && sortedRows.length === 0;

  const EmptyState = (
    <div className="rounded border bg-white p-6 text-sm text-slate-700">
      <div className="font-semibold">No stories found.</div>
      <div className="mt-1 text-xs text-slate-600">Try clearing filters or create a new story.</div>
    </div>
  );

  const RowBadges = ({ a }: { a: Article }) => {
    const tags = getTags(a).map((t) => norm(t));
    const pti = needsPtiReview(a);
    const ai = isAiVerified(a);

    return (
      <div className="flex flex-wrap gap-1">
        {pti && <span className="px-2 py-0.5 rounded-full bg-amber-700 text-white text-[10px]">PTI</span>}
        {ai && <span className="px-2 py-0.5 rounded-full bg-indigo-600 text-white text-[10px]">AI-Verified</span>}
        {tags.includes('flagged') && <span className="px-2 py-0.5 rounded-full bg-red-700 text-white text-[10px]">Flagged</span>}
      </div>
    );
  };

  const LocationBadge = ({ a }: { a: Article }) => {
    const loc = getLocationTags(a);
    if (!loc.length) return <span className="text-slate-500 text-xs">—</span>;
    const firstTwo = loc.slice(0, 2);
    const rest = loc.length - firstTwo.length;
    return (
      <div className="flex items-center gap-1 flex-wrap">
        {firstTwo.map((t) => (
          <span key={t} className="px-2 py-0.5 rounded-full bg-slate-100 text-slate-700 text-[11px] border">{t}</span>
        ))}
        {rest > 0 && <span className="px-2 py-0.5 rounded-full bg-slate-100 text-slate-700 text-[11px] border">+{rest}</span>}
      </div>
    );
  };

  const renderActions = (a: Article) => {
    const st = (a.status ?? 'draft') as ArticleStatus;
    const id = a._id;
    const baseLogPayload = {
      clickedArticleId: id,
      slug: String(a.slug || ''),
      language: String((a as any).lang ?? a.language ?? ''),
      translationGroupId: String((a as any).translationGroupId || ''),
      status: st,
      relatedArticleIds: [],
    };

    return (
      <div className="flex items-center justify-end gap-3 flex-nowrap whitespace-nowrap">
        <ActionLink
          label="Edit"
          tone="blue"
          onClick={() => {
            logNewsTableAction('edit click', {
              ...baseLogPayload,
              route: `/admin/articles/${encodeURIComponent(id)}/edit`,
            });
            navigate(`/admin/articles/${id}/edit`);
          }}
        />

        {st === 'draft' && (
          <>
            <ActionLink
              label="Publish"
              title={publishEnabled ? 'Publish' : 'Publish (disabled)'}
              tone="green"
              disabled={!publishEnabled}
              onClick={() => {
                if (!publishEnabled) return;
                logNewsTableAction('publish click', {
                  ...baseLogPayload,
                  route: `/admin-api/articles/${encodeURIComponent(id)}`,
                  payload: { status: 'published' },
                });
                mutatePublish.mutate(id);
              }}
            />
            <ActionLink
              label="Schedule"
              title={publishEnabled ? 'Schedule…' : 'Schedule (disabled)'}
              tone="amber"
              disabled={!publishEnabled}
              onClick={() => {
                if (!publishEnabled) return;
                logNewsTableAction('schedule click', {
                  ...baseLogPayload,
                  route: `/admin-api/articles/${encodeURIComponent(id)}`,
                });
                setScheduleTarget(a);
                setScheduleOpen(true);
              }}
            />
          </>
        )}

        {st === 'scheduled' && (
          <ActionLink
            label="Unschedule"
            tone="amber"
            onClick={() => {
              logNewsTableAction('unschedule click', {
                ...baseLogPayload,
                route: `/admin-api/articles/${encodeURIComponent(id)}`,
                payload: { status: 'draft', publishAt: null, scheduledAt: null },
              });
              mutateUnschedule.mutate(id);
            }}
          />
        )}

        {st === 'published' && (
          <ActionLink
            label="Unpublish"
            tone="slate"
            onClick={() => {
              logNewsTableAction('unpublish click', {
                ...baseLogPayload,
                route: `/admin-api/articles/${encodeURIComponent(id)}`,
                payload: { status: 'draft' },
              });
              mutateUnpublish.mutate(id);
            }}
          />
        )}

        {st !== 'archived' && canArchive && (
          <ActionLink
            label="Archive"
            tone="slate"
            onClick={() => mutateArchive.mutate(id)}
          />
        )}

        {(st === 'archived' || st === 'deleted') && canArchive && (
          <ActionLink
            label="Restore"
            tone="blue"
            onClick={() => mutateRestore.mutate(id)}
          />
        )}

        {st !== 'deleted' && canDelete && (
          <ActionLink
            label="Delete"
            tone="red"
            onClick={() => mutateDelete.mutate(id)}
          />
        )}

        {st === 'deleted' && canDelete && (
          <ActionLink
            label="Delete forever"
            tone="red"
            onClick={() => {
              const ok = confirm('Delete forever? This will permanently delete this article and cannot be undone.');
              if (ok) mutateDeleteHard.mutate(id);
            }}
          />
        )}
      </div>
    );
  };

  const thBase = 'sticky z-30 bg-slate-50 px-3 py-3 text-left text-xs font-semibold uppercase tracking-wide text-slate-600 border-b border-slate-200';
  const thRight = `${thBase} text-right`;
  const thStyle: React.CSSProperties = { top: effectiveStickyTop };

  const renderAnalyticsCell = (id: string, field: 'views' | 'readers' | 'engaged' | 'avg' | 'completion') => {
    if (!showAnalyticsCols) return null;
    if (analyticsQuery.isLoading) return <span className="text-xs text-slate-500">…</span>;
    if (analyticsQuery.isError) return <span className="text-xs text-slate-500">—</span>;
    const row = analyticsById.get(id);
    if (!row) return <span className="text-xs text-slate-500">—</span>;
    if (field === 'views') return <span className="text-xs font-semibold text-slate-800">{formatNumberCompact(row.views)}</span>;
    if (field === 'readers') return <span className="text-xs text-slate-700">{formatNumberCompact((row.uniqueReaders ?? row.readers) as any)}</span>;
    if (field === 'engaged') return <span className="text-xs text-slate-700">{formatNumberCompact(row.engagedReads)}</span>;
    if (field === 'avg') return <span className="text-xs text-slate-700">{formatDurationShort(row.avgReadTimeSec)}</span>;
    return <span className="text-xs text-slate-700">{formatPercent(row.completionRate)}</span>;
  };

  return (
    <div className="space-y-3">
      <div className="flex items-center justify-between gap-2">
        <div className="text-xs text-slate-600">Showing {sortedRows.length} of {total} loaded</div>
        <div className="flex items-center gap-2">
          <label className="flex items-center gap-2 text-xs font-semibold text-slate-700">
            <input
              type="checkbox"
              checked={showAnalyticsCols}
              onChange={(e) => setShowAnalyticsCols(e.target.checked)}
            />
            Analytics columns
          </label>
          {showAnalyticsCols ? (
            <select
              value={analyticsRange}
              onChange={(e) => setAnalyticsRange(e.target.value as any)}
              className="rounded-md border border-slate-200 bg-white px-2 py-1 text-xs font-semibold text-slate-700"
              title="Analytics range"
            >
              <option value="24h">24h</option>
              <option value="7d">7d</option>
              <option value="30d">30d</option>
            </select>
          ) : null}
        </div>
        {(params.status === 'deleted' || (params.status as any) === 'trash') && canDelete && selected.length > 0 ? (
          <button
            type="button"
            disabled={bulkDeleting}
            onClick={() => {
              const ids = [...selected];
              const count = ids.length;
              if (count <= 0) return;
              const ok = confirm(`Delete ${count} article${count === 1 ? '' : 's'} forever? This cannot be undone.`);
              if (!ok) return;
              mutateDeleteHardBulk.mutate(ids);
            }}
            className={
              'rounded-md px-3 py-2 text-xs font-semibold '
              + (bulkDeleting ? 'bg-slate-200 text-slate-500 cursor-not-allowed' : 'bg-red-700 text-white hover:bg-red-800')
            }
          >
            {bulkDeleting ? 'Deleting…' : `Delete Selected Forever (${selected.length})`}
          </button>
        ) : null}
      </div>

      {showSkeleton ? (
        <div className="relative isolate rounded-xl border border-slate-200 bg-white">
          <div ref={stickySentinelRef} className="h-0" aria-hidden="true" />
          <div className="overflow-x-auto">
            <table className={showAnalyticsCols ? 'min-w-[1500px] w-full border-separate border-spacing-0' : 'min-w-[1240px] w-full border-separate border-spacing-0'}>
              <thead className="bg-slate-50">
                <tr className="bg-slate-50">
                  <th className={thBase} style={thStyle}>
