          </div>
          {liveSponsoredFeature ? (
            <div className="mt-3 grid grid-cols-1 gap-3 text-sm md:grid-cols-4">
              {(() => {
                const commercialState = getSponsoredFeatureCommercialState(
                  liveSponsoredFeature,
                  liveSponsoredFeature.optionalLinkedSponsoredArticleId
                    ? sponsoredArticleById.get(liveSponsoredFeature.optionalLinkedSponsoredArticleId) || null
                    : null,
                );
                return (
                  <>
              <div>
                <div className="text-xs font-semibold uppercase tracking-wide text-slate-400">Headline</div>
                <div className="mt-1 text-slate-900">{liveSponsoredFeature.headline}</div>
              </div>
              <div>
                <div className="text-xs font-semibold uppercase tracking-wide text-slate-400">Public click target</div>
                <div className="mt-1 break-all text-slate-900">{commercialState.publicClickTarget || '-'}</div>
              </div>
              <div>
                <div className="text-xs font-semibold uppercase tracking-wide text-slate-400">Commercial product</div>
                <div className="mt-1 text-slate-900">{commercialState.productLabel}</div>
              </div>
              <div>
                <div className="text-xs font-semibold uppercase tracking-wide text-slate-400">Combo Campaign</div>
                <div className="mt-1 text-slate-900">{commercialState.comboLabel}</div>
              </div>
                  </>
                );
              })()}
            </div>
          ) : (
            <div className="mt-3 text-sm text-slate-500">{homepageVisibilityBlocker || 'No active homepage Sponsored Feature yet. Create one here and mark it active.'}</div>
          )}
        </div>

        <div className="mt-4 grid grid-cols-1 gap-4 lg:grid-cols-[minmax(0,2fr),minmax(320px,1fr)]">
          <div className="space-y-4">
            {sponsoredFeaturesLoading ? (
              <div className="rounded border border-slate-200 bg-white p-5 text-sm text-slate-500">Loading Sponsored Features…</div>
            ) : sponsoredFeatures.length > 0 ? (
              sponsoredFeatures.map((feature) => {
                const busy = Boolean(sponsoredFeatureBusyById[feature.id]);
                const comboIsActive = feature.comboCampaignIsActive !== false;
                const visibility = getSponsoredFeatureVisibility(feature);
                const scheduleLabel = feature.startAt || feature.endAt ? formatAdScheduleRange(feature.startAt, feature.endAt) : 'Always available';
                const linkedArticle = feature.optionalLinkedSponsoredArticleId
                  ? sponsoredArticleById.get(feature.optionalLinkedSponsoredArticleId) || null
                  : null;
                const commercialState = getSponsoredFeatureCommercialState(feature, linkedArticle);
                return (
                  <div key={feature.id} className="rounded border border-slate-200 bg-white p-4 shadow-sm">
                    <div className="flex flex-wrap items-start justify-between gap-3">
                      <div>
                        <div className="text-xs font-semibold uppercase tracking-[0.18em] text-slate-400">Sponsored Feature</div>
                        <div className="mt-1 text-lg font-semibold text-slate-900">{feature.headline || 'Untitled Sponsored Feature'}</div>
                        <div className="mt-1 text-sm text-slate-600">{feature.sponsorName || 'Sponsor name missing'}</div>
                      </div>
                      <div className="flex flex-wrap items-center gap-2">
                        <button
                          type="button"
                          onClick={() => void toggleSponsoredFeatureActive(feature)}
                          disabled={busy}
                          className={`rounded border px-3 py-1.5 text-xs font-medium ${feature.isActive ? 'border-green-600 bg-green-600 text-white' : 'border-slate-300 bg-slate-100 text-slate-800'}`}
                        >
                          {busy ? 'Saving…' : visibility.homepageToggleLabel}
                        </button>
                        <span className={`inline-flex rounded-full border px-2.5 py-1 text-[11px] font-medium ${feature.isActive ? 'border-emerald-200 bg-emerald-50 text-emerald-800' : 'border-slate-200 bg-slate-50 text-slate-700'}`}>
                          {feature.isActive ? 'Homepage ON' : 'Homepage OFF'}
                        </span>
                        <span className={`inline-flex rounded-full border px-2.5 py-1 text-[11px] font-medium ${visibility.className}`}>
                          {visibility.label}
                        </span>
                      </div>
                    </div>

                    {feature.shortSummary ? (
                      <p className="mt-3 text-sm leading-6 text-slate-700">{feature.shortSummary}</p>
                    ) : null}

                    <div className="mt-3 rounded border border-slate-200 bg-slate-50 px-3 py-2 text-xs text-slate-600">
                      <span className="font-semibold text-slate-900">Homepage status:</span> {visibility.helperText}
                    </div>

                    <div className="mt-4 grid grid-cols-1 gap-3 text-sm text-slate-600 md:grid-cols-2">
                      <div>
                        <div className="text-xs font-semibold uppercase tracking-wide text-slate-400">CTA</div>
                        <div className="mt-1">{feature.ctaText || '-'}</div>
                      </div>
                      <div>
                        <div className="text-xs font-semibold uppercase tracking-wide text-slate-400">Schedule</div>
                        <div className="mt-1">{scheduleLabel}</div>
                      </div>
                      <div>
                        <div className="text-xs font-semibold uppercase tracking-wide text-slate-400">Linked Sponsored Article</div>
                        <div className="mt-1">{feature.linkedSponsoredArticleTitle || feature.optionalLinkedSponsoredArticleId || 'No linked Sponsored Article'}</div>
                        <div className="mt-1 text-xs text-slate-500">{commercialState.linkedArticleLabel}</div>
                      </div>
                      <div>
                        <div className="text-xs font-semibold uppercase tracking-wide text-slate-400">Destination fallback</div>
                        <div className="mt-1 break-all">{feature.destinationUrl || '-'}</div>
                      </div>
                      <div>
                        <div className="text-xs font-semibold uppercase tracking-wide text-slate-400">Public click target</div>
                        <div className="mt-1 break-all">{commercialState.publicClickTarget || '-'}</div>
                      </div>
                      <div>
                        <div className="text-xs font-semibold uppercase tracking-wide text-slate-400">Commercial product</div>
                        <div className="mt-1">{commercialState.productLabel}</div>
                        <div className="mt-1 text-xs text-slate-500">{commercialState.productHelp}</div>
                      </div>
                      <div>
                        <div className="text-xs font-semibold uppercase tracking-wide text-slate-400">Combo Campaign</div>
                        <div className="mt-1">{commercialState.comboLabel}</div>
                        <div className="mt-1 text-xs text-slate-500">{commercialState.comboHelp}</div>
                      </div>
                    </div>

                    <div className="mt-4 flex flex-wrap gap-2">
                      <button
                        type="button"
                        onClick={() => void toggleSponsoredFeatureCombo(feature)}
                        disabled={busy || !feature.optionalLinkedSponsoredArticleId}
                        className={`rounded border px-3 py-1.5 text-xs font-medium ${comboIsActive ? 'border-amber-500 bg-amber-500 text-white' : 'border-slate-300 bg-slate-100 text-slate-800'} disabled:cursor-not-allowed disabled:opacity-60`}
                      >
                        {busy ? 'Saving…' : (comboIsActive ? 'Combo Off' : 'Combo On')}
                      </button>
                      <button
                        type="button"
                        onClick={() => openEditSponsoredFeature(feature)}
                        disabled={busy}
                        className="rounded border border-slate-300 px-3 py-1.5 text-xs font-medium text-slate-800 hover:bg-slate-50"
                      >
                        Edit Sponsored Feature
                      </button>
                      <button
                        type="button"
                        onClick={() => void removeSponsoredFeature(feature)}
                        disabled={busy}
                        className="rounded border border-red-300 px-3 py-1.5 text-xs font-medium text-red-700 hover:bg-red-50"
                      >
                        Delete
                      </button>
                    </div>
                  </div>
                );
              })
            ) : (
              <div className="rounded border border-dashed border-slate-300 bg-slate-50 p-6 text-sm text-slate-600">
                No Sponsored Features yet. Create one here when you need a homepage sponsored campaign.
              </div>
            )}
          </div>

          <div className="space-y-4">
            <div className="rounded border border-slate-200 bg-white p-4 shadow-sm">
              <div className="text-sm font-medium">Recent Sponsored Articles</div>
              <div className="mt-1 text-xs text-slate-600">Standalone Sponsored Articles keep their own publish state. Published ones are eligible for Combo linking.</div>
              <div className="mt-3 space-y-2">
                {sponsoredArticlesLoading ? (
                  <div className="text-xs text-slate-500">Loading Sponsored Articles…</div>
                ) : sponsoredArticleInventory.length > 0 ? (
                  sponsoredArticleInventory.slice(0, 8).map((article) => {
                    const articleLive = isSponsoredArticleLiveStatus(article.status);
                    const busy = Boolean(sponsoredArticleBusyById[article.id]);
                    return (
                      <div key={article.id} className="rounded border border-slate-200 bg-slate-50 px-3 py-2 text-sm">
                        <div className="flex items-start justify-between gap-2">
                          <div>
                            <div className="font-medium text-slate-900">{article.title}</div>
                            <div className="mt-1 text-xs text-slate-500">{article.publicUrl || article.id}{article.status ? ` • ${article.status}` : ''}</div>
                            <div className="mt-1 text-[11px] text-slate-500">{getSponsoredArticleStatusLabel(article)}</div>
                          </div>
                          <button
                            type="button"
                            onClick={() => void toggleSponsoredArticleActive(article)}
                            disabled={busy}
                            className={`shrink-0 rounded border px-2.5 py-1 text-[11px] font-medium ${articleLive ? 'border-blue-600 bg-blue-600 text-white' : 'border-slate-300 bg-white text-slate-700'} disabled:cursor-not-allowed disabled:opacity-60`}
                          >
                            {busy ? 'Saving…' : (articleLive ? 'Article Off' : 'Article On')}
                          </button>
                        </div>
                      </div>
                    );
                  })
                ) : (
                  <div className="text-xs text-slate-500">No eligible Sponsored Articles found yet.</div>
                )}
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Filters */}
      <div className="flex flex-wrap items-center gap-4 bg-slate-50 dark:bg-slate-800 border rounded p-3">
        <div className="flex items-center gap-2">
          <label className="text-sm font-medium">Slot</label>
          <select
            className="border rounded px-2 py-1 text-sm bg-white dark:bg-slate-900"
            value={slotFilter}
            onChange={(e) => setSlotFilter(e.target.value as any)}
          >
            <option value="ALL">All</option>
            {SLOT_OPTIONS.map(s => (
              <option key={s} value={s}>{slotLabel(String(s))}</option>
            ))}
          </select>
        </div>

        <label className="flex items-center gap-2 text-sm">
          <input
            type="checkbox"
            checked={activeOnly}
            onChange={(e) => setActiveOnly(e.target.checked)}
          />
          Active only
        </label>

        <div className="text-xs text-slate-500">
          Showing <span className="font-medium">{filteredAds.length}</span>
        </div>
      </div>

      {/* Ad Placements */}
      <div className="border rounded p-4 bg-white dark:bg-slate-900">
        <div className="flex items-center justify-between gap-3">
          <h2 className="text-lg font-semibold">Ad Placements</h2>
          <button
            type="button"
            onClick={() => void loadSettings()}
            className="px-3 py-1 rounded border text-sm"
            disabled={settingsLoading}
          >
            {settingsLoading ? 'Loading…' : 'Refresh'}
          </button>
        </div>

        <div className="mt-3 grid grid-cols-1 md:grid-cols-2 gap-3">
          {PLACEMENT_SLOT_OPTIONS.map((key) => (
            <div
              key={key}
              className="border rounded p-3 bg-slate-50 dark:bg-slate-950 flex items-center justify-between gap-3"
            >
              <div>
                <div className="text-sm font-medium">{slotLabel(key)}</div>
                <div className="text-xs text-slate-500 font-mono">{key}</div>
              </div>
              <button
                type="button"
                disabled={settingsLoading || placementSaving[key]}
                onClick={() => void togglePlacement(key)}
                className={`px-3 py-1 rounded text-xs border min-w-[84px] ${placementSaving[key] ? 'cursor-not-allowed opacity-80' : ''} ${slotEnabled[key] ? 'bg-green-600 text-white border-green-600' : 'bg-slate-200 text-slate-700 border-slate-300'}`}
                title="Toggle placement"
              >
                {placementSaving[key] ? 'Saving…' : (slotEnabled[key] ? 'ON' : 'OFF')}
              </button>
            </div>
          ))}
        </div>
      </div>

      {/* Table */}
      <div className="overflow-auto border rounded">
        <table className="min-w-[980px] w-full text-sm">
          <thead className="bg-slate-100 dark:bg-slate-900">
            <tr>
              <th className="text-left p-2">Slot</th>
              <th className="text-left p-2">Title</th>
              <th className="text-left p-2">Active</th>
              <th className="text-left p-2">Schedule</th>
              <th className="text-left p-2">Priority</th>
              <th className="text-left p-2">Updated</th>
              <th className="text-left p-2">Preview</th>
              <th className="text-left p-2">Actions</th>
            </tr>
          </thead>
          <tbody>
            {loading ? (
              <tr>
                <td className="p-3 text-slate-500" colSpan={8}>Loading…</td>
              </tr>
            ) : filteredAds.length === 0 ? (
              <tr>
                <td className="p-3 text-slate-500" colSpan={8}>No ads found.</td>
              </tr>
            ) : (
              filteredAds.map(ad => {
                const busy = Boolean(rowBusy[ad.id]);
                const updatedLabel = safeDateLabel(ad.updatedAt || ad.createdAt);
                const scheduleLabel = formatAdScheduleRange(ad.startAt, ad.endAt);
                const isBrokenImage = Boolean(ad.imageUrl) && Boolean(brokenImageByAdId[ad.id]);

                return (
                  <tr key={ad.id} className="border-t">
                    <td className="p-2">
                      <div className="text-sm font-medium">{displayPlacementLabel(ad)}</div>
                      <div className="font-mono text-[11px] text-slate-500">{String(ad.slot || '-')}</div>
                    </td>
                    <td className="p-2">
                      <div>{ad.headline || ad.title || '-'}</div>
                      {ad.sponsorBrandName ? <div className="text-[11px] text-slate-500">{ad.sponsorBrandName}</div> : null}
                    </td>
                    <td className="p-2">
                      <button
                        type="button"
                        disabled={busy}
                        onClick={() => void toggleActive(ad)}
                        className={`px-2 py-1 rounded text-xs border min-w-[44px] ${ad.isActive ? 'bg-green-600 text-white border-green-600' : 'bg-slate-200 text-slate-700 border-slate-300'}`}
                        title="Toggle active"
                      >
                        {busy ? '...' : (ad.isActive ? 'ON' : 'OFF')}
                      </button>
                    </td>
                    <td className="p-2 text-xs text-slate-600 dark:text-slate-300">{scheduleLabel}</td>
                    <td className="p-2">{Number(ad.priority ?? 0)}</td>
                    <td className="p-2 text-xs text-slate-600 dark:text-slate-300">{updatedLabel}</td>
                    <td className="p-2">
                      <div className="flex items-center gap-2">
                        <div className="w-[120px] h-[40px] bg-slate-100 dark:bg-slate-900 border rounded overflow-hidden flex items-center justify-center">
                          {ad.imageUrl ? (
                            // eslint-disable-next-line @typescript-eslint/no-misused-promises
                            <img
                              src={ad.imageUrl}
                              alt={ad.title || ad.slot}
                              className="max-w-full max-h-full object-contain"
                              onError={() => setBrokenImageByAdId((prev) => ({ ...prev, [ad.id]: true }))}
                              onLoad={() => setBrokenImageByAdId((prev) => (prev[ad.id] ? ({ ...prev, [ad.id]: false }) : prev))}
                            />
                          ) : (
                            <span className="text-xs text-slate-400">No image</span>
                          )}
                        </div>
                        {isBrokenImage ? (
                          <span className="text-[11px] text-red-700">Image URL invalid</span>
                        ) : (
                          <span className="text-[11px] text-slate-500">{isSponsoredFeatureAd(ad) ? 'Sponsored Feature' : 'Click target'}</span>
                        )}
                      </div>
                    </td>
                    <td className="p-2">
                      <div className="flex flex-wrap gap-2">
                        <button
                          type="button"
                          onClick={() => openEdit(ad)}
                          className="px-2 py-1 rounded border text-xs"
                          disabled={busy}
                        >
                          Edit
                        </button>
                        <button
                          type="button"
                          onClick={() => void removeAd(ad)}
                          className="px-2 py-1 rounded border text-xs text-red-700 border-red-300 hover:bg-red-50"
                          disabled={busy}
                        >
                          Delete
                        </button>
                      </div>
                    </td>
                  </tr>
                );
              })
            )}
          </tbody>
        </table>
      </div>

      {/* Create/Edit Modal */}
      {modalOpen && (
        <div
          className="fixed inset-0 z-50 bg-black/50 flex items-center justify-center px-3 py-4"
          role="dialog"
          aria-modal="true"
        >
          <div
            className="bg-white dark:bg-slate-900 rounded border shadow flex flex-col overflow-hidden"
            style={{
              maxHeight: 'calc(100vh - 32px)',
              width: 'min(920px, calc(100vw - 24px))',
            }}
          >
            <div className="flex items-center justify-between p-4 border-b flex-none">
              <h2 className="text-lg font-semibold">
                {form.mode === 'sponsored-feature'
                  ? (editingId ? 'Edit Sponsored Feature' : 'Create Sponsored Feature')
                  : (editingId ? 'Edit Ad' : 'Create Ad')}
              </h2>
              <button
                type="button"
                onClick={closeModal}
                className="px-2 py-1 rounded border"
                disabled={saving}
              >
                Close
              </button>
            </div>

            <form onSubmit={submit} className="flex flex-col flex-1 min-h-0">
              <div className="flex-1 min-h-0 overflow-y-auto py-5 px-6 overscroll-contain">
                <div className="space-y-4">
                  {form.mode === 'sponsored-feature' ? (
                    <div className="rounded-lg border border-amber-200 bg-amber-50 px-4 py-3 text-sm text-amber-950">
                      <div className="font-semibold">Sponsored Feature</div>
                      <div className="mt-1">Premium homepage promo card with image, headline, short summary, CTA, and click destination.</div>
                      <div className="mt-2 text-xs">For Combo campaigns, publish the Sponsored Article first, then link it from the Sponsored Feature.</div>
                    </div>
                  ) : null}

                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {form.mode === 'sponsored-feature' ? (
                  <>
                    <div className="space-y-1">
                      <label className="text-sm font-medium">Placement *</label>
                      <select
                        className="w-full border rounded px-2 py-2 bg-white dark:bg-slate-950"
                        value={form.placement}
                        onChange={(e) => setForm(prev => ({ ...prev, placement: e.target.value as SponsoredContentPlacement }))}
                      >
                        {SPONSORED_FEATURE_PLACEMENTS.map((placement) => (
                          <option key={placement.value} value={placement.value}>{placement.label}</option>
                        ))}
                      </select>
                    </div>

                    <div className="space-y-1">
                      <label className="text-sm font-medium">Sponsor / Brand Name *</label>
                      <input
                        className="w-full border rounded px-2 py-2"
                        value={form.sponsorBrandName}
                        onChange={(e) => setForm(prev => ({ ...prev, sponsorBrandName: e.target.value }))}
                        placeholder="Enter sponsor or brand name"
                      />
                    </div>

                    <div className="space-y-1">
                      <label className="text-sm font-medium">Internal Campaign Name</label>
                      <input
                        className="w-full border rounded px-2 py-2"
                        value={form.internalCampaignName}
                        onChange={(e) => setForm(prev => ({ ...prev, internalCampaignName: e.target.value }))}
                        placeholder="Optional internal label"
                      />
                    </div>

                    <div className="space-y-1">
                      <label className="text-sm font-medium">Headline *</label>
                      <input
                        className="w-full border rounded px-2 py-2"
                        value={form.headline}
                        onChange={(e) => setForm(prev => ({ ...prev, headline: e.target.value }))}
                        placeholder="Homepage headline"
                      />
                    </div>

                    <div className="space-y-1 md:col-span-2">
                      <label className="text-sm font-medium">Short Summary *</label>
                      <textarea
                        className="w-full border rounded px-2 py-2"
                        rows={3}
                        value={form.shortSummary}
                        onChange={(e) => setForm(prev => ({ ...prev, shortSummary: e.target.value }))}
                        placeholder="Short homepage summary"
                      />
                    </div>

                    <div className="space-y-1">
                      <label className="text-sm font-medium">CTA Text *</label>
                      <input
                        className="w-full border rounded px-2 py-2"
                        value={form.ctaText}
                        onChange={(e) => setForm(prev => ({ ...prev, ctaText: e.target.value }))}
                        placeholder="Example: Read More"
                      />
                    </div>

                    <div className="space-y-1">
                      <label className="text-sm font-medium">Destination URL {form.linkedSponsoredArticleId ? '(fallback)' : '*'}</label>
                      <input
                        className="w-full border rounded px-2 py-2"
                        value={form.destinationUrl}
                        onChange={(e) => setForm(prev => ({ ...prev, destinationUrl: e.target.value }))}
                        placeholder="https://... or /news/..."
                      />
                      <div className="text-[11px] text-slate-500">Used when no Sponsored Article is linked, or as the fallback destination.</div>
                    </div>
                  </>
                ) : (
                  <>
                    <div className="space-y-1">
                      <label className="text-sm font-medium">Slot *</label>
                      {editingId && isLegacySlot(form.slot) ? (
                        <div className="w-full border rounded px-2 py-2 bg-slate-50 dark:bg-slate-950">
                          <div className="text-sm">{slotLabel(String(form.slot))}</div>
                          <div className="text-xs text-slate-500 font-mono">{canonicalSlot(form.slot)}</div>
                        </div>
                      ) : (
                        <select
                          className="w-full border rounded px-2 py-2 bg-white dark:bg-slate-950"
                          value={form.slot}
                          onChange={(e) => setForm(prev => ({ ...prev, slot: e.target.value as any }))}
                          required
                        >
                          <option value="">Select slot…</option>
                          {SLOT_OPTIONS.map(s => (
                            <option key={s} value={s}>{slotDropdownLabel(String(s))}</option>
                          ))}
                        </select>
                      )}
                    </div>

                    <div className="space-y-1">
                      <label className="text-sm font-medium">Title *</label>
                      <input
                        className="w-full border rounded px-2 py-2"
                        value={form.title}
                        onChange={(e) => setForm(prev => ({ ...prev, title: e.target.value }))}
                        placeholder="e.g. Sponsor: ACME"
                      />
                    </div>
                  </>
                )}

                <div className="space-y-1 md:col-span-2">
                  <label className="text-sm font-medium">{form.mode === 'sponsored-feature' ? 'Cover Image *' : 'Image URL *'}</label>
                  <input
                    className="w-full border rounded px-2 py-2"
                    value={form.imageUrl}
                    onChange={(e) => setForm(prev => ({ ...prev, imageUrl: e.target.value }))}
                    placeholder="https://..."
                    required
                  />

                  {form.mode === 'standard-ad' && isExternalImageUrl(form.imageUrl) ? (
                    <div className="mt-2 flex flex-wrap items-center gap-2">
                      <button
                        type="button"
                        className="px-3 py-1.5 rounded border text-sm disabled:opacity-60"
                        disabled={saving || hostingExternalImage || !editingId}
                        onClick={() => void hostExternalImageNow()}
                        title={editingId ? 'Ask backend to re-host this image' : 'Create the ad first, then you can host the image'}
                      >
                        {hostingExternalImage ? 'Hosting…' : 'Host this image'}
                      </button>
                      {!editingId ? (
                        <span className="text-xs text-slate-500">Will be hosted on Create Ad</span>
                      ) : null}
                    </div>
                  ) : null}

                  <div className="mt-2 flex flex-wrap items-center gap-2">
                    <input
                      type="file"
                      accept="image/*"
                      className="text-sm"
                      disabled={adImageUploading}
                      onChange={(e) => {
                        const f = e.currentTarget.files?.[0] || null;
                        setAdImageFile(f);
                      }}
                    />
                    <button
                      type="button"
                      className="px-3 py-1.5 rounded border text-sm disabled:opacity-60"
                      disabled={adImageUploading || !adImageFile}
                      onClick={() => void handleUploadSelectedImage()}
                      title="Upload selected image"
                    >
                      {adImageUploading
                        ? (typeof adImageUploadProgress === 'number' ? `Uploading… ${adImageUploadProgress}%` : 'Uploading…')
                        : 'Upload Image'}
                    </button>
