            disabled={!!props.disabled}
            checked={props.enabled}
            onChange={(e) => props.onEnabledChange(e.target.checked)}
          />
          Enabled
        </label>
      </div>

      <div className="mt-4 flex flex-col gap-3">
        <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
          <label className="text-sm font-semibold text-slate-800 dark:text-slate-200">Mode</label>
          <select
            value={props.mode}
            onChange={(e) => props.onModeChange(e.target.value as 'manual' | 'auto')}
            disabled={!!props.disabled}
            className="w-full rounded-lg border border-slate-200 bg-white px-3 py-2 text-sm dark:border-slate-700 dark:bg-slate-950 sm:w-72"
          >
            <option value="manual">Force ON</option>
            <option value="auto">Auto</option>
          </select>
        </div>

        {typeof props.tickerSpeedSeconds === 'number' && typeof props.onTickerSpeedSecondsChange === 'function' ? (
          <div className="space-y-2">
            <div className="flex flex-col gap-2 sm:flex-row sm:items-start sm:justify-between">
              <div>
                <label className="text-sm font-semibold text-slate-800 dark:text-slate-200">Scroll duration (seconds)</label>
                <div className="mt-0.5 text-xs text-slate-500 dark:text-slate-400">Higher = slower = more readable</div>
                <div className="mt-0.5 text-xs text-slate-500 dark:text-slate-400">Recommended range: 12–30 seconds</div>
              </div>

              <div className="flex flex-col items-stretch gap-2 sm:w-72">
                <PresetsRow
                  value={duration}
                  onChange={(next) => props.onTickerSpeedSecondsChange?.(clampDurationSeconds(next, durationFallback))}
                  disabled={!!props.disabled}
                />

                <div className="flex items-center gap-3">
                  <input
                    type="range"
                    min={12}
                    max={30}
                    step={1}
                    value={duration}
                    onChange={(e) => props.onTickerSpeedSecondsChange?.(clampDurationSeconds(e.target.value, durationFallback))}
                    disabled={!!props.disabled}
                    className="w-full"
                    aria-label="Scroll duration"
                  />
                  <div className="w-12 text-right text-sm font-semibold text-slate-900 dark:text-white">
                    {duration}
                  </div>
                </div>

                {typeof props.onTickerSpeedSecondsReset === 'function' ? (
                  <div className="flex justify-end">
                    <button
                      type="button"
                      className="text-xs font-semibold text-slate-500 hover:text-slate-900 dark:text-slate-400 dark:hover:text-white"
                      onClick={() => props.onTickerSpeedSecondsReset?.()}
                    >
                      Reset
                    </button>
                  </div>
                ) : null}
              </div>
            </div>

            {/* Live preview (simple marquee) */}
            <div className="rounded-xl border border-slate-200 bg-slate-50 p-3 dark:border-slate-700 dark:bg-slate-950">
              <div className="mb-2 flex items-center justify-between">
                <div className="text-xs font-semibold uppercase tracking-wide text-slate-500 dark:text-slate-400">Live preview</div>
                <div className="text-xs font-semibold text-slate-500 dark:text-slate-400">{duration}s</div>
              </div>
              <div className="relative overflow-hidden rounded-lg border border-slate-200 bg-white px-3 py-2 text-sm text-slate-700 dark:border-slate-800 dark:bg-slate-900 dark:text-slate-200">
                <style>{`@keyframes np-marquee { 0% { transform: translateX(100%); } 100% { transform: translateX(-120%); } }`}</style>
                <div
                    key={`np-marquee-${duration}`}
                  style={{
                    display: 'inline-block',
                    whiteSpace: 'nowrap',
                    willChange: 'transform',
                    animation: `np-marquee ${duration}s linear infinite`,
                  }}
                >
                  Live preview — Fast (12s) vs Normal (20s) vs Slow (30s) should be obvious • Live preview — Fast (12s) vs Normal (20s) vs Slow (30s) should be obvious • Live preview — Fast (12s) vs Normal (20s) vs Slow (30s) should be obvious.
                </div>
              </div>
            </div>
          </div>
        ) : null}

        <div className="flex flex-col gap-2 sm:flex-row">
          <input
            value={props.inputValue}
            onChange={(e) => props.onInputChange(e.target.value)}
            maxLength={160}
            placeholder="Add story (max 160 chars)"
            className="w-full flex-1 rounded-lg border border-slate-200 bg-white px-3 py-2 text-sm dark:border-slate-700 dark:bg-slate-950"
          />

          <select
            value={props.langChoice}
            onChange={(e) => props.onLangChoiceChange(e.target.value as LangChoice)}
            disabled={props.addDisabled || !!props.disabled}
            className="w-full rounded-lg border border-slate-200 bg-white px-3 py-2 text-sm dark:border-slate-700 dark:bg-slate-950 sm:w-44"
            aria-label="Language of this ticker"
          >
            {SOURCE_LANG_OPTIONS.map((opt) => (
              <option key={opt.value} value={opt.value}>
                {opt.label}
              </option>
            ))}
          </select>

          <button
            type="button"
            className="rounded-lg bg-slate-900 px-4 py-2 text-sm font-semibold text-white hover:bg-slate-800 disabled:opacity-50 dark:bg-white dark:text-slate-900 dark:hover:bg-slate-200"
            disabled={props.addDisabled || !!props.disabled}
            onClick={props.onAdd}
          >
            Add
          </button>
        </div>

        <div className="flex flex-wrap items-center justify-between gap-2">
          <div className="text-xs text-slate-500 dark:text-slate-400">
            Language of this ticker:{' '}
            <span className="font-semibold text-slate-700 dark:text-slate-200">
              {props.langChoice === 'auto' ? `Auto (${props.detectedLang.toUpperCase()})` : props.langChoice.toUpperCase()}
            </span>
          </div>

          <label className="inline-flex items-center gap-2 text-xs font-semibold text-slate-700 dark:text-slate-200">
            <input
              type="checkbox"
              className="h-4 w-4"
              checked={props.previewEnabled}
              onChange={(e) => props.onPreviewEnabledChange(e.target.checked)}
              disabled={!!props.disabled}
            />
            Preview translations
          </label>
        </div>

        {props.previewEnabled ? (
          <div className="rounded-xl border border-slate-200 bg-slate-50 p-3 text-xs dark:border-slate-700 dark:bg-slate-950">
            {props.preview?.error ? (
              <div className="text-amber-800 dark:text-amber-200">Preview failed: {props.preview.error}</div>
            ) : props.preview?.loading ? (
              <div className="text-slate-500 dark:text-slate-400">Translating…</div>
            ) : (
              <div className="grid grid-cols-1 gap-2 sm:grid-cols-3">
                {(['en', 'hi', 'gu'] as const).map((k) => (
                  <div key={k} className="rounded-lg border border-slate-200 bg-white p-2 dark:border-slate-800 dark:bg-slate-900">
                    <div className="mb-1 font-semibold text-slate-600 dark:text-slate-300">
                      {k === 'en' ? 'English' : k === 'hi' ? 'Hindi' : 'Gujarati'}
                    </div>
                    <div className="text-slate-900 dark:text-white break-words">
                      {(props.preview as any)?.[k] || '—'}
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        ) : null}

        <div className="rounded-xl border border-slate-200 dark:border-slate-700">
          {itemsSorted.length === 0 ? (
            <div className="p-4 text-sm text-slate-600 dark:text-slate-300">No recent stories found</div>
          ) : (
            <div className="divide-y divide-slate-200 dark:divide-slate-700">
              {itemsSorted.map((it) => {
                let itemId: string | null = null;
                try {
                  itemId = getBroadcastItemId(it as any);
                } catch {
                  itemId = null;
                }
                const busy = itemId ? !!props.workingIdMap[itemId] : false;
                return (
                  <div key={itemId ?? `${it.createdAt}-${it.text}`} className="flex items-start gap-3 p-4">
                    <input type="checkbox" className="mt-1 h-4 w-4" aria-label="Select item" />
                    <div className="min-w-0 flex-1">
                      <div className="flex items-start justify-between gap-2">
                        <div className="text-sm font-semibold text-slate-900 dark:text-white break-words">{it.text}</div>
                      </div>
                      <div className="mt-1 text-xs text-slate-500 dark:text-slate-400">
                        Created {formatLocalTime(it.createdAt)} • Expires in {expiresIn(it.expiresAt)}
                      </div>
                    </div>

                    <button
                      type="button"
                      className="rounded-lg border border-slate-200 bg-white px-3 py-1.5 text-xs font-semibold text-slate-900 hover:bg-slate-50 disabled:opacity-50 dark:border-slate-700 dark:bg-slate-900 dark:text-white dark:hover:bg-slate-800"
                      disabled={busy || !itemId}
                      onClick={() => {
                        props.onDelete(it);
                      }}
                    >
                      Delete
                    </button>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>
    </section>
  );
}

export default function BroadcastCenter() {
  const notify = useNotify();
  const notifyRef = useRef(notify);
  useEffect(() => { notifyRef.current = notify; }, [notify]);
  const [activeTab, setActiveTab] = useState<BroadcastCenterTab>('breaking');

  const [proxyHealthy, setProxyHealthy] = useState<boolean | null>(null);
  const [proxyHealthStatus, setProxyHealthStatus] = useState<number | null>(null);
  const proxyHealthyRef = useRef<boolean | null>(proxyHealthy);
  useEffect(() => { proxyHealthyRef.current = proxyHealthy; }, [proxyHealthy]);

  const ensureProxyHealthy = useCallback(async (opts?: { force?: boolean }) => {
    // If we already confirmed the proxy is reachable, do not re-check unless forced.
    if (!opts?.force && proxyHealthyRef.current === true) return true;

    const health = await checkProxyHealth();
    setProxyHealthy(health.ok);
    setProxyHealthStatus(typeof health.status === 'number' ? health.status : null);
    if (!health.ok) notifyProxyMissingOnce(notifyRef.current);
    return health.ok;
  }, []);

  const didInitialLoad = useRef(false);
  const lastSavedRef = useRef<string>(serializeSaveKey(DEFAULT_SETTINGS, DEFAULT_TICKER_SPEED_SECONDS, DEFAULT_TICKER_SPEED_SECONDS));
  const refreshInFlight = useRef(false);

  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [lastRefreshAt, setLastRefreshAt] = useState<string | null>(null);

  const [settings, setSettings] = useState<BroadcastSettings>(() => DEFAULT_SETTINGS);

  const [breakingLangChoice, setBreakingLangChoice] = useState<LangChoice>('auto');
  const [liveLangChoice, setLiveLangChoice] = useState<LangChoice>('auto');

  const [glossary, setGlossary] = useState<GlossaryEntry[]>([]);

  const [breakingPreviewEnabled, setBreakingPreviewEnabled] = useState(false);
  const [livePreviewEnabled, setLivePreviewEnabled] = useState(false);

  const [breakingPreview, setBreakingPreview] = useState<{ en?: string; hi?: string; gu?: string; loading?: boolean; error?: string | null }>({});
  const [livePreview, setLivePreview] = useState<{ en?: string; hi?: string; gu?: string; loading?: boolean; error?: string | null }>({});

  const [publicPreview, setPublicPreview] = useState<{
    loading: boolean;
    error?: string | null;
    breaking: Record<SourceLang, string[]>;
    live: Record<SourceLang, string[]>;
  }>(() => ({
    loading: false,
    error: null,
    breaking: { en: [], hi: [], gu: [] },
    live: { en: [], hi: [], gu: [] },
  }));

  const [breakingTickerSpeedSeconds, setBreakingTickerSpeedSeconds] = useState<number>(() => normalizeSpeeds(null).breakingTickerSpeedSeconds);
  const [liveTickerSpeedSeconds, setLiveTickerSpeedSeconds] = useState<number>(() => normalizeSpeeds(null).liveTickerSpeedSeconds);

  const [breakingText, setBreakingText] = useState('');
  const [liveText, setLiveText] = useState('');

  const [breakingItems, setBreakingItems] = useState<BroadcastItem[]>([]);
  const [liveItems, setLiveItems] = useState<BroadcastItem[]>([]);

  const [workingIdMap, setWorkingIdMap] = useState<Record<string, boolean>>({});
  const [addingType, setAddingType] = useState<BroadcastType | null>(null);

  useEffect(() => {
    let mounted = true;
    (async () => {
      try {
        const res = await fetch('/admin-api/admin/translation/glossary', {
          method: 'GET',
          cache: 'no-store',
          credentials: 'include',
          headers: { Accept: 'application/json' },
        });
        if (!res.ok) return;
        const data: any = await res.json().catch(() => null);
        const items = Array.isArray(data) ? data : Array.isArray(data?.items) ? data.items : [];
        if (!mounted) return;
        setGlossary(items);
      } catch {
        // non-blocking
      }
    })();
    return () => {
      mounted = false;
    };
  }, []);

  const translatePreview = useCallback(async (text: string, from: SourceLang) => {
    const trimmed = String(text || '').trim();
    if (!trimmed) return { en: '', hi: '', gu: '' };

    const baseText = applyGlossary(trimmed, glossary, from);

    const translateOne = async (to: SourceLang): Promise<string> => {
      if (to === from) return baseText;
      const res = await fetch('/admin-api/language/translate', {
        method: 'POST',
        cache: 'no-store',
        credentials: 'include',
        headers: {
          'Content-Type': 'application/json',
          Accept: 'application/json',
        },
        body: JSON.stringify({ text: baseText, from, to }),
      });
      if (!res.ok) {
        const txt = await res.text().catch(() => '');
        throw new Error(`HTTP ${res.status} ${res.statusText}${txt ? ` • ${txt.slice(0, 120)}` : ''}`);
      }
      const data: any = await res.json().catch(() => null);
      const translated = String(data?.translated ?? data?.text ?? '').trim();
      return applyGlossary(translated || baseText, glossary, to);
    };

    const [en, hi, gu] = await Promise.all([
      translateOne('en'),
      translateOne('hi'),
      translateOne('gu'),
    ]);
    return { en, hi, gu };
  }, [glossary]);

  const breakingDetectedLang = useMemo(() => detectLangFromText(breakingText), [breakingText]);
  const liveDetectedLang = useMemo(() => detectLangFromText(liveText), [liveText]);

  useEffect(() => {
    if (!breakingPreviewEnabled) return;
    const t = breakingText.trim();
    if (!t) {
      setBreakingPreview({ en: '', hi: '', gu: '', loading: false, error: null });
      return;
    }
    const from: SourceLang = breakingLangChoice === 'auto' ? breakingDetectedLang : breakingLangChoice;
    let alive = true;
    setBreakingPreview((prev) => ({ ...prev, loading: true, error: null }));
    const timer = setTimeout(() => {
      void (async () => {
        try {
          const out = await translatePreview(t, from);
          if (!alive) return;
          setBreakingPreview({ ...out, loading: false, error: null });
        } catch (e: any) {
          if (!alive) return;
          setBreakingPreview({ loading: false, error: e?.message || 'Translation failed' });
        }
      })();
    }, 300);
    return () => {
      alive = false;
      clearTimeout(timer);
    };
  }, [breakingPreviewEnabled, breakingText, breakingLangChoice, breakingDetectedLang, translatePreview]);

  useEffect(() => {
    if (!livePreviewEnabled) return;
    const t = liveText.trim();
    if (!t) {
      setLivePreview({ en: '', hi: '', gu: '', loading: false, error: null });
      return;
    }
    const from: SourceLang = liveLangChoice === 'auto' ? liveDetectedLang : liveLangChoice;
    let alive = true;
    setLivePreview((prev) => ({ ...prev, loading: true, error: null }));
    const timer = setTimeout(() => {
      void (async () => {
        try {
          const out = await translatePreview(t, from);
          if (!alive) return;
          setLivePreview({ ...out, loading: false, error: null });
        } catch (e: any) {
          if (!alive) return;
          setLivePreview({ loading: false, error: e?.message || 'Translation failed' });
        }
      })();
    }, 300);
    return () => {
      alive = false;
      clearTimeout(timer);
    };
  }, [livePreviewEnabled, liveText, liveLangChoice, liveDetectedLang, translatePreview]);

  const fetchPublicPreview = useCallback(async () => {
    setPublicPreview((prev) => ({ ...prev, loading: true, error: null }));
    try {
      const fetchOne = async (type: BroadcastType, lang: SourceLang): Promise<string[]> => {
        const url = `/admin-api/public/broadcast?type=${encodeURIComponent(type)}&lang=${encodeURIComponent(lang)}`;
        const res = await fetch(url, {
          method: 'GET',
          cache: 'no-store',
          credentials: 'include',
          headers: { Accept: 'application/json' },
        });

        if (!res.ok) {
          const txt = await res.text().catch(() => '');
          throw new Error(`HTTP ${res.status} ${res.statusText}${txt ? ` • ${txt.slice(0, 120)}` : ''}`);
        }

        const data: any = await res.json().catch(() => null);
        const items = Array.isArray(data)
          ? data
          : Array.isArray(data?.items)
            ? data.items
            : Array.isArray(data?.data?.items)
              ? data.data.items
              : [];

        return (items || [])
          .map((it: any) => String(it?.text ?? it?.headline ?? it ?? '').trim())
          .filter(Boolean)
          .slice(0, 6);
      };

      const [breakingEn, breakingHi, breakingGu, liveEn, liveHi, liveGu] = await Promise.all([
        fetchOne('breaking', 'en'),
        fetchOne('breaking', 'hi'),
        fetchOne('breaking', 'gu'),
        fetchOne('live', 'en'),
        fetchOne('live', 'hi'),
        fetchOne('live', 'gu'),
      ]);

      setPublicPreview({
        loading: false,
        error: null,
        breaking: { en: breakingEn, hi: breakingHi, gu: breakingGu },
        live: { en: liveEn, hi: liveHi, gu: liveGu },
      });
    } catch (e: any) {
      setPublicPreview((prev) => ({
        ...prev,
        loading: false,
        error: e?.message || 'Failed to load public preview',
      }));
    }
  }, []);

  const setWorking = useCallback((id: string, next: boolean) => {
    setWorkingIdMap((prev) => {
      if (prev[id] === next) return prev;
      return { ...prev, [id]: next };
    });
  }, []);

  const loadAll = useCallback(async (_signal?: AbortSignal) => {
    // Load config first; do not fail the whole page if a secondary history endpoint is missing.
    const broadcastRes = await apiGetBroadcastConfig();

    // If this call succeeded, the proxy is definitely reachable.
    setProxyHealthy(true);

    const broadcastObj = unwrapObj(broadcastRes);
    const rawSettings = unwrapObj((broadcastObj as any)?.settings ?? broadcastObj) as any;

    // Backends vary: some store settings flat (breakingEnabled), others nested (breaking.enabled).
    // Read both shapes so enabled/mode don't appear to "reset" after save/refresh.
    const breakingEnabled = pickBoolean(
      rawSettings?.breaking?.enabled,
      rawSettings?.breakingEnabled,
      (broadcastObj as any)?.breaking?.enabled,
      (broadcastObj as any)?.breakingEnabled,
    );
    const liveEnabled = pickBoolean(
      rawSettings?.live?.enabled,
      rawSettings?.liveEnabled,
      (broadcastObj as any)?.live?.enabled,
      (broadcastObj as any)?.liveEnabled,
    );
    const breakingMode = pickMode(
      rawSettings?.breaking?.mode,
      rawSettings?.breakingMode,
      (broadcastObj as any)?.breaking?.mode,
      (broadcastObj as any)?.breakingMode,
    );
    const liveMode = pickMode(
      rawSettings?.live?.mode,
      rawSettings?.liveMode,
      (broadcastObj as any)?.live?.mode,
      (broadcastObj as any)?.liveMode,
    );

    const settingsObj: BroadcastSettings = {
      breakingEnabled,
      breakingMode,
      liveEnabled,
      liveMode,
    };

    const [breakingRes, liveRes] = await Promise.allSettled([
      apiListBroadcastItems('breaking'),
      apiListBroadcastItems('live'),
    ]);

    if (breakingRes.status === 'fulfilled') {
      setBreakingItems(normalizeItems(breakingRes.value as any));
    } else {
      setBreakingItems([]);
      notifyRef.current.err('Breaking history unavailable', apiErrorDetails(breakingRes.reason, 'API error'));
    }

    if (liveRes.status === 'fulfilled') {
      setLiveItems(normalizeItems(liveRes.value as any));
    } else {
      setLiveItems([]);
      notifyRef.current.err('Live history unavailable', apiErrorDetails(liveRes.reason, 'API error'));
    }

    const fromBroadcastBreaking = pickDurationSeconds(broadcastObj, 'breaking') ?? pickDurationSeconds((broadcastObj as any)?.settings, 'breaking');
    const fromBroadcastLive = pickDurationSeconds(broadcastObj, 'live') ?? pickDurationSeconds((broadcastObj as any)?.settings, 'live');

    const fallbackSpeeds = normalizeSpeeds(null);
    const breakingDur = typeof fromBroadcastBreaking === 'number' ? fromBroadcastBreaking : fallbackSpeeds.breakingTickerSpeedSeconds;
    const liveDur = typeof fromBroadcastLive === 'number' ? fromBroadcastLive : fallbackSpeeds.liveTickerSpeedSeconds;

    const nextBreaking = clampDurationSeconds(breakingDur, 12);
    const nextLive = clampDurationSeconds(liveDur, 12);

    setSettings(settingsObj);
    setBreakingTickerSpeedSeconds(nextBreaking);
    setLiveTickerSpeedSeconds(nextLive);
    lastSavedRef.current = serializeSaveKey(settingsObj, nextBreaking, nextLive);
  }, []);

  const doSave = useCallback(async (
    nextSettings: BroadcastSettings,
    nextBreakingSec: number,
    nextLiveSec: number,
    opts?: { toast?: string }
  ) => {
    if (saving) return;
    setSaving(true);
    try {
      const breakingTickerSpeedSeconds = clampDurationSeconds(nextBreakingSec, 12);
      const liveTickerSpeedSeconds = clampDurationSeconds(nextLiveSec, 12);

      const savedKey = serializeSaveKey(nextSettings, breakingTickerSpeedSeconds, liveTickerSpeedSeconds);

      // Normalized backend payload (per contract)
      const payload = {
        breaking: {
          enabled: !!nextSettings.breakingEnabled,
          mode: toBackendMode(nextSettings.breakingMode),
          durationSec: breakingTickerSpeedSeconds,
        },
        live: {
          enabled: !!nextSettings.liveEnabled,
          mode: toBackendMode(nextSettings.liveMode),
          durationSec: liveTickerSpeedSeconds,
        },
      };

      await apiSaveBroadcastConfig(payload);

      // Save succeeded: proxy definitely reachable.
      setProxyHealthy(true);

      // Merge-safe: re-fetch the canonical server config so we don't accidentally
      // reset the other ticker if the backend applies defaults.
      try {
        const broadcastRes = await apiGetBroadcastConfig();
        const broadcastObj = unwrapObj(broadcastRes);
        const rawSettings = unwrapObj((broadcastObj as any)?.settings ?? broadcastObj) as any;

        const breakingEnabled = pickBoolean(
          rawSettings?.breaking?.enabled,
          rawSettings?.breakingEnabled,
          (broadcastObj as any)?.breaking?.enabled,
          (broadcastObj as any)?.breakingEnabled,
        );
        const liveEnabled = pickBoolean(
          rawSettings?.live?.enabled,
          rawSettings?.liveEnabled,
          (broadcastObj as any)?.live?.enabled,
          (broadcastObj as any)?.liveEnabled,
        );
        const breakingMode = pickMode(
          rawSettings?.breaking?.mode,
          rawSettings?.breakingMode,
          (broadcastObj as any)?.breaking?.mode,
          (broadcastObj as any)?.breakingMode,
        );
        const liveMode = pickMode(
          rawSettings?.live?.mode,
          rawSettings?.liveMode,
          (broadcastObj as any)?.live?.mode,
          (broadcastObj as any)?.liveMode,
        );

        const settingsObj: BroadcastSettings = {
          breakingEnabled,
          breakingMode,
          liveEnabled,
          liveMode,
        };

        const fromBroadcastBreaking = pickDurationSeconds(broadcastObj, 'breaking') ?? pickDurationSeconds((broadcastObj as any)?.settings, 'breaking');
        const fromBroadcastLive = pickDurationSeconds(broadcastObj, 'live') ?? pickDurationSeconds((broadcastObj as any)?.settings, 'live');

        const nextBreaking = clampDurationSeconds(typeof fromBroadcastBreaking === 'number' ? fromBroadcastBreaking : breakingTickerSpeedSeconds, 12);
        const nextLive = clampDurationSeconds(typeof fromBroadcastLive === 'number' ? fromBroadcastLive : liveTickerSpeedSeconds, 12);

        setSettings(settingsObj);
        setBreakingTickerSpeedSeconds(nextBreaking);
        setLiveTickerSpeedSeconds(nextLive);
        lastSavedRef.current = serializeSaveKey(settingsObj, nextBreaking, nextLive);
        setLastRefreshAt(new Date().toISOString());
      } catch {
        // If refresh fails, keep the optimistic UI state.
        setSettings(nextSettings);
        setBreakingTickerSpeedSeconds(breakingTickerSpeedSeconds);
        setLiveTickerSpeedSeconds(liveTickerSpeedSeconds);
        lastSavedRef.current = savedKey;
      }

      notifyRef.current.ok(opts?.toast || 'Saved. Live will update within 10 seconds.');

      // Refresh public preview (best-effort). If the backend doesn't support this endpoint yet,
      // the preview will show an error but the save still succeeded.
      void fetchPublicPreview();
    } catch (e: any) {
      try {
        console.error('[BroadcastCenter] Save failed', {
          method: 'PUT',
          url: '/admin-api/admin/broadcast',
          error: e,
        });
      } catch {}
      if (isMethodNotAllowed(e)) {
        notifyRef.current.err('Save failed', 'Backend method not allowed (405). Expected PUT/POST /api/admin/broadcast.');
        return;
      }
      if (isUnauthorized(e)) {
        notifyRef.current.err('Session expired — please login again');
        return;
      }

      // Non-blocking: warn if proxy health check fails, but still show the real error.
      void ensureProxyHealthy({ force: true });
      notifyRef.current.err('Save failed', apiErrorDetails(e, 'API error'));
    } finally {
      setSaving(false);
    }
  }, [saving, ensureProxyHealthy]);

  const dirty = useMemo(() => {
    const nowKey = serializeSaveKey(settings, breakingTickerSpeedSeconds, liveTickerSpeedSeconds);
    return !!nowKey && nowKey !== lastSavedRef.current;
  }, [settings, breakingTickerSpeedSeconds, liveTickerSpeedSeconds]);

  const refreshAll = useCallback(async () => {
    if (refreshInFlight.current) return;
    refreshInFlight.current = true;
    setIsRefreshing(true);
    try {
      // Non-blocking warning if /admin-api/system/health fails.
      void ensureProxyHealthy({ force: true });
      await loadAll();
      setLastRefreshAt(new Date().toISOString());
    } catch (e: any) {
      void ensureProxyHealthy({ force: true });
      if (isMethodNotAllowed(e)) {
        notifyRef.current.err('Refresh failed', 'Backend method not allowed (405).');
      } else {
        notifyRef.current.err('Refresh failed', apiErrorDetails(e, 'API error'));
      }
    } finally {
      refreshInFlight.current = false;
      setIsRefreshing(false);
    }
  }, [loadAll, ensureProxyHealthy]);

  useEffect(() => {
    let mounted = true;
    (async () => {
      if (didInitialLoad.current) return;
      didInitialLoad.current = true;
      try {
        await refreshAll();
      } catch (e: any) {
        if (isMethodNotAllowed(e)) {
          notifyRef.current.err('Load failed', 'Backend method not allowed (405).');
        } else if (isUnauthorized(e)) {
          notifyRef.current.err('Session expired — please login again');
        } else {
          notifyRef.current.err('Load failed', apiErrorDetails(e, 'API error'));
        }
      } finally {
        if (mounted) setLoading(false);
      }
    })();
    return () => {
      mounted = false;
    };
  }, [refreshAll]);

  const addItem = useCallback(async (type: BroadcastType) => {
    const text = (type === 'breaking' ? breakingText : liveText).trim();
    if (!text) {
      notifyRef.current.err('Cannot add empty story');
      return;
    }
    if (text.length > 160) {
      notifyRef.current.err('Story is too long', 'Max 160 characters');
      return;
    }
    setAddingType(type);
    try {
      const choice: LangChoice = type === 'breaking' ? breakingLangChoice : liveLangChoice;
      const detected: SourceLang = type === 'breaking' ? detectLangFromText(breakingText) : detectLangFromText(liveText);
      const sourceLang: SourceLang = choice === 'auto' ? detected : choice;
      const createdItem = await apiAddBroadcastItem(type, text, { sourceLang });
      if (type === 'breaking') setBreakingText('');
      else setLiveText('');

      // Always refresh the list after add for canonical state.
      // (Some backends don't return the created item.)
      const items = await apiListBroadcastItems(type);
      if (type === 'breaking') setBreakingItems(items);
      else setLiveItems(items);

      // Keep an optimistic feel if we did get an item back (it should already be included after refresh).
      void createdItem;
    } catch (e: any) {
      try {
        console.error('[BroadcastCenter] Add failed', {
          method: 'POST',
          url: '/admin-api/admin/broadcast/items',
          type,
          error: e,
        });
      } catch {}
      if (isUnauthorized(e)) {
        notifyRef.current.err('Session expired — please login again');
        return;
      }
      if (isMethodNotAllowed(e)) {
        notifyRef.current.err('Add failed', 'Backend route missing or method not allowed (POST). Check backend /broadcast/items POST route.');
        return;
      }
      notifyRef.current.err('Add failed', apiErrorDetails(e, 'API error'));
    } finally {
      setAddingType(null);
    }
  }, [breakingText, liveText, breakingLangChoice, liveLangChoice]);

  const deleteItem = useCallback(async (type: BroadcastType, item: BroadcastItem) => {
    const itemId = (item as any)?.id ?? (item as any)?._id;
    if (!itemId) {
      notifyRef.current.err('Delete failed', 'Missing item id');
      return;
    }
    const id = String(itemId);
    setWorking(id, true);
    try {
      await apiDeleteBroadcastItem(id);
      // Optimistic UI removal (then refresh for canonical state)
      if (type === 'breaking') setBreakingItems((prev) => prev.filter((it: any) => (it?._id ?? it?.id) !== id));
      else setLiveItems((prev) => prev.filter((it: any) => (it?._id ?? it?.id) !== id));

      const items = await apiListBroadcastItems(type);
      if (type === 'breaking') setBreakingItems(items);
      else setLiveItems(items);
    } catch (e: any) {
      try {
        console.error('[BroadcastCenter] Delete failed', {
          method: 'DELETE',
          url: `/admin-api/admin/broadcast/items/${encodeURIComponent(id)}`,
          type,
          id,
          error: e,
        });
      } catch {}
      if (isUnauthorized(e)) {
        notifyRef.current.err('Session expired — please login again');
        return;
      }
      notifyRef.current.err('Delete failed', apiErrorDetails(e, 'API error'));
    } finally {
      setWorking(id, false);
    }
  }, [setWorking]);

  return (
    <div className="space-y-6">
      {proxyHealthy === false ? (
        <div className="rounded-xl border border-amber-200 bg-amber-50 p-4 text-amber-900 dark:border-amber-900/40 dark:bg-amber-950/40 dark:text-amber-100">
          <div className="text-sm font-semibold">Admin API proxy warning</div>
          <div className="mt-1 text-xs opacity-90">
            Health probe to <span className="font-mono">/admin-api/system/health</span> failed{typeof proxyHealthStatus === 'number' ? ` (HTTP ${proxyHealthStatus || 0})` : ''}. You can still try Save/Refresh; if this is local dev, ensure the Vite proxy target is set.
          </div>
          {(() => {
            const direct = String(
              (import.meta as any)?.env?.VITE_BACKEND_URL ||
              (import.meta as any)?.env?.VITE_PROXY_TARGET ||
              (import.meta as any)?.env?.VITE_BACKEND_ORIGIN ||
              ''
            ).trim();
            if (!direct) return null;
            return (
              <div className="mt-3 flex flex-wrap items-center gap-2">
                <div className="text-xs">Backend:</div>
                <div className="rounded-md bg-white/70 px-2 py-1 text-xs font-mono dark:bg-black/30">{direct}</div>
                <button
                  type="button"
                  className="rounded-lg border border-amber-300 bg-white px-3 py-1.5 text-xs font-semibold hover:bg-amber-100 dark:border-amber-800 dark:bg-amber-950 dark:hover:bg-amber-900/50"
                  onClick={async () => {
                    try {
                      await navigator.clipboard.writeText(direct);
                      notifyRef.current.ok('Copied backend URL');
                    } catch {
                      notifyRef.current.err('Copy failed');
                    }
                  }}
                >
                  Copy
                </button>
              </div>
            );
          })()}
        </div>
      ) : null}

      <header className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
        <div className="space-y-1">
          <h1 className="text-2xl font-bold tracking-tight">📡 Broadcast Center</h1>
          <p className="text-sm text-slate-600 dark:text-slate-300">Manage Breaking, Live Updates, and paid ticker ads in separate workflows.</p>
        </div>

        <div className="flex flex-wrap items-center gap-3">
          {activeTab === 'ticker-ads' && dirty ? (
            <div className="rounded-full bg-amber-50 px-3 py-1 text-xs font-semibold text-amber-800 dark:bg-amber-950/40 dark:text-amber-200">
              Breaking/Live changes pending on other tabs
            </div>
          ) : null}
          {activeTab !== 'ticker-ads' ? (
            <>
              <button
                type="button"
                className="rounded-lg bg-slate-900 px-4 py-2 text-sm font-semibold text-white hover:bg-slate-800 disabled:opacity-50 dark:bg-white dark:text-slate-900 dark:hover:bg-slate-200"
                disabled={loading || saving || !dirty}
                onClick={() => {
                  void doSave(settings, breakingTickerSpeedSeconds, liveTickerSpeedSeconds);
                }}
              >
                {saving ? 'Saving…' : 'Save'}
              </button>
              <button
                type="button"
                className="rounded-lg border border-slate-200 bg-white px-4 py-2 text-sm font-semibold text-slate-900 hover:bg-slate-50 disabled:opacity-50 dark:border-slate-700 dark:bg-slate-900 dark:text-white dark:hover:bg-slate-800"
                disabled={isRefreshing}
                onClick={() => {
                  void refreshAll();
                }}
              >
                {isRefreshing ? 'Refreshing…' : 'Refresh LIVE'}
              </button>
            </>
          ) : null}
        </div>
      </header>

      <section className="rounded-2xl border border-slate-200 bg-white p-3 dark:border-slate-700 dark:bg-slate-900">
        <div className="flex flex-wrap gap-2">
          {BROADCAST_CENTER_TABS.map((tab) => {
            const active = activeTab === tab.key;
            return (
              <button
                key={tab.key}
                type="button"
                onClick={() => setActiveTab(tab.key)}
                className={
                  'rounded-full border px-4 py-2 text-sm font-semibold transition ' +
                  (active
                    ? 'border-slate-900 bg-slate-900 text-white dark:border-white dark:bg-white dark:text-slate-900'
                    : 'border-slate-200 bg-white text-slate-700 hover:bg-slate-50 dark:border-slate-700 dark:bg-slate-900 dark:text-slate-200 dark:hover:bg-slate-800')
                }
              >
                {tab.label}
              </button>
            );
          })}
        </div>
        <div className="mt-2 text-xs text-slate-500 dark:text-slate-400">
          {BROADCAST_CENTER_TABS.find((tab) => tab.key === activeTab)?.note}
        </div>
      </section>

      {activeTab !== 'ticker-ads' && lastRefreshAt ? (
        <div className="text-xs text-slate-500 dark:text-slate-400">Last refreshed {formatLocalTime(lastRefreshAt)}</div>
      ) : null}

      {activeTab !== 'ticker-ads' ? (
      <section className="rounded-2xl border border-slate-200 bg-white p-5 dark:border-slate-700 dark:bg-slate-900">
        <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
          <div>
            <div className="text-sm font-semibold">Public ticker preview (EN/HI/GU)</div>
            <div className="mt-0.5 text-xs text-slate-500 dark:text-slate-400">
              Fetches <span className="font-mono">/admin-api/public/broadcast</span> for both tickers.
            </div>
          </div>

          <button
            type="button"
            className="rounded-lg border border-slate-200 bg-white px-4 py-2 text-sm font-semibold text-slate-900 hover:bg-slate-50 disabled:opacity-50 dark:border-slate-700 dark:bg-slate-900 dark:text-white dark:hover:bg-slate-800"
            disabled={publicPreview.loading}
            onClick={() => void fetchPublicPreview()}
          >
            {publicPreview.loading ? 'Loading…' : 'Refresh preview'}
          </button>
        </div>

        {publicPreview.error ? (
          <div className="mt-3 rounded-xl border border-amber-200 bg-amber-50 p-3 text-xs text-amber-900 dark:border-amber-900/40 dark:bg-amber-950/40 dark:text-amber-100">
            Preview unavailable: {publicPreview.error}
          </div>
        ) : null}

        <div className="mt-4 grid grid-cols-1 gap-4 lg:grid-cols-2">
          {(['breaking', 'live'] as const).map((type) => (
            <div key={type} className="rounded-xl border border-slate-200 p-4 dark:border-slate-700">
              <div className="text-xs font-semibold uppercase tracking-wide text-slate-500 dark:text-slate-400">
                {type === 'breaking' ? 'Breaking' : 'Live Updates'}
              </div>

              <div className="mt-3 grid grid-cols-1 gap-3 sm:grid-cols-3">
                {(['en', 'hi', 'gu'] as const).map((lang) => {
                  const lines = (type === 'breaking' ? publicPreview.breaking : publicPreview.live)[lang];
                  return (
                    <div key={lang} className="rounded-lg border border-slate-200 bg-slate-50 p-3 text-xs dark:border-slate-700 dark:bg-slate-950">
                      <div className="mb-2 font-semibold text-slate-700 dark:text-slate-200">
                        {lang === 'en' ? 'English' : lang === 'hi' ? 'Hindi' : 'Gujarati'}
                      </div>
                      {lines.length === 0 ? (
                        <div className="text-slate-500 dark:text-slate-400">No lines</div>
                      ) : (
                        <div className="space-y-1">
                          {lines.map((t, i) => (
                            <div key={`${lang}-${i}`} className="truncate" title={t}>
                              {t}
                            </div>
                          ))}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            </div>
          ))}
        </div>
      </section>
      ) : null}

      {activeTab === 'breaking' ? (
      <div className="grid grid-cols-1 gap-6">
        <SectionCard
          title="🔥 Breaking"
          disabled={loading}
          enabled={settings.breakingEnabled}
          onEnabledChange={(next) => {
            // Backend treats mode=force_on as always-on; if user disables, also move to Auto.
            setSettings((prev) => ({
              ...prev,
              breakingEnabled: next,
              ...(next ? null : { breakingMode: 'auto' }),
            }));
          }}
          mode={settings.breakingMode}
          onModeChange={(next) => setSettings((prev) => ({ ...prev, breakingMode: next }))}
          tickerSpeedSeconds={breakingTickerSpeedSeconds}
          onTickerSpeedSecondsChange={(next) => setBreakingTickerSpeedSeconds(clampDurationSeconds(next, 12))}
          defaultTickerSpeedSeconds={12}
          onTickerSpeedSecondsReset={() => setBreakingTickerSpeedSeconds(12)}
          inputValue={breakingText}
          onInputChange={setBreakingText}
          langChoice={breakingLangChoice}
          onLangChoiceChange={setBreakingLangChoice}
          detectedLang={breakingDetectedLang}
          previewEnabled={breakingPreviewEnabled}
          onPreviewEnabledChange={setBreakingPreviewEnabled}
          preview={breakingPreview}
          addDisabled={loading || addingType === 'breaking'}
          onAdd={() => addItem('breaking')}
          items={breakingItems}
          workingIdMap={workingIdMap}
          onDelete={(item) => deleteItem('breaking', item)}
        />
      </div>
      ) : null}

      {activeTab === 'live' ? (
      <div className="grid grid-cols-1 gap-6">
        <SectionCard
          title="🔵 Live Updates"
          disabled={loading}
          enabled={settings.liveEnabled}
          onEnabledChange={(next) => {
            setSettings((prev) => ({
              ...prev,
              liveEnabled: next,
              ...(next ? null : { liveMode: 'auto' }),
            }));
          }}
          mode={settings.liveMode}
          onModeChange={(next) => setSettings((prev) => ({ ...prev, liveMode: next }))}
          tickerSpeedSeconds={liveTickerSpeedSeconds}
          onTickerSpeedSecondsChange={(next) => setLiveTickerSpeedSeconds(clampDurationSeconds(next, 12))}
          defaultTickerSpeedSeconds={12}
          onTickerSpeedSecondsReset={() => setLiveTickerSpeedSeconds(12)}
          inputValue={liveText}
          onInputChange={setLiveText}
          langChoice={liveLangChoice}
          onLangChoiceChange={setLiveLangChoice}
          detectedLang={liveDetectedLang}
          previewEnabled={livePreviewEnabled}
          onPreviewEnabledChange={setLivePreviewEnabled}
          preview={livePreview}
          addDisabled={loading || addingType === 'live'}
          onAdd={() => addItem('live')}
          items={liveItems}
          workingIdMap={workingIdMap}
          onDelete={(item) => deleteItem('live', item)}
        />
      </div>
      ) : null}

      {activeTab === 'ticker-ads' ? <BroadcastCenterTickerAds /> : null}
    </div>
  );
}

import { useEffect, useMemo, useRef, useState } from 'react';
import ConfirmModal from '@/components/ui/ConfirmModal';
import Switch from '@/components/settings/Switch';
import { useNotify } from '@/components/ui/toast-bridge';
import {
  createTickerAd,
  deleteTickerAd,
  listTickerAds,
  type TickerAd,
  type TickerAdChannel,
  type TickerAdDayPart,
  type TickerAdLanguage,
  type TickerAdMutation,
  updateTickerAd,
} from '@/api/tickerAds';
import { AdminApiError } from '@/lib/http/adminFetch';

const CHANNEL_OPTIONS: Array<{ value: TickerAdChannel; label: string }> = [
  { value: 'breaking', label: 'Breaking' },
  { value: 'live', label: 'Live Updates' },
  { value: 'both', label: 'Both' },
];

const LANGUAGE_OPTIONS: Array<{ value: TickerAdLanguage; label: string }> = [
  { value: 'all', label: 'All Languages (EN+HI+GU)' },
  { value: 'en', label: 'English' },
  { value: 'hi', label: 'Hindi' },
  { value: 'gu', label: 'Gujarati' },
];

const DAY_PART_OPTIONS: Array<{ value: TickerAdDayPart; label: string }> = [
  { value: 'morning', label: 'Morning' },
  { value: 'noon', label: 'Noon' },
  { value: 'evening', label: 'Evening' },
  { value: 'night', label: 'Night' },
];

type FormState = {
  message: string;
  messageEn: string;
  messageHi: string;
  messageGu: string;
  url: string;
  channel: TickerAdChannel;
  language: TickerAdLanguage;
  startAtLocal: string;
  endAtLocal: string;
  dayParts: TickerAdDayPart[];
  priority: string;
  frequency: number;
  active: boolean;
};

type FormErrors = Partial<Record<'message' | 'messageEn' | 'messageHi' | 'messageGu' | 'url' | 'startAtLocal' | 'endAtLocal', string>>;

function normalizeLanguageCode(value: unknown): TickerAdLanguage {
  const normalized = String(value || '').trim().toLowerCase();
  if (normalized === 'all' || normalized === 'all languages' || normalized === 'all-languages' || normalized === 'all_languages') return 'all';
  if (normalized === 'hindi' || normalized === 'hi') return 'hi';
  if (normalized === 'gujarati' || normalized === 'gu') return 'gu';
  return 'en';
}

function normalizeDayPartCode(value: unknown): TickerAdDayPart | null {
  const normalized = String(value || '').trim().toLowerCase();
  if (normalized === 'morning') return 'morning';
  if (normalized === 'noon') return 'noon';
  if (normalized === 'evening') return 'evening';
  if (normalized === 'night') return 'night';
  return null;
}

function normalizeDayPartsCodes(value: unknown): TickerAdDayPart[] {
  const rawValues = Array.isArray(value) ? value : typeof value === 'string' ? value.split(/[|,]/g) : [];
  const unique = new Set<TickerAdDayPart>();
  for (const raw of rawValues) {
    const normalized = normalizeDayPartCode(raw);
    if (normalized) unique.add(normalized);
  }
  return Array.from(unique);
}

function pad(value: number): string {
  return String(value).padStart(2, '0');
}

function toLocalInputValue(iso: string): string {
  if (!iso) return '';
  const date = new Date(iso);
  if (Number.isNaN(date.getTime())) return '';
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}T${pad(date.getHours())}:${pad(date.getMinutes())}`;
}

function fromLocalInputValue(value: string): string {
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return '';
  return date.toISOString();
}

function createEmptyForm(): FormState {
  const start = new Date();
  const end = new Date(start.getTime() + 60 * 60 * 1000);
  return {
    message: '',
    messageEn: '',
    messageHi: '',
    messageGu: '',
    url: '',
    channel: 'both',
    language: 'en',
    startAtLocal: toLocalInputValue(start.toISOString()),
    endAtLocal: toLocalInputValue(end.toISOString()),
    dayParts: [],
    priority: '0',
    frequency: 1,
    active: true,
  };
}

function formFromAd(ad: TickerAd): FormState {
  return {
    message: ad.message,
    messageEn: ad.messages?.en || (ad.language === 'en' ? ad.message : ''),
    messageHi: ad.messages?.hi || (ad.language === 'hi' ? ad.message : ''),
    messageGu: ad.messages?.gu || (ad.language === 'gu' ? ad.message : ''),
    url: ad.url || '',
    channel: ad.channel,
    language: normalizeLanguageCode(ad.language),
    startAtLocal: toLocalInputValue(ad.startAt),
    endAtLocal: toLocalInputValue(ad.endAt),
    dayParts: normalizeDayPartsCodes(ad.dayParts),
    priority: String(ad.priority),
    frequency: ad.frequency,
    active: ad.active,
  };
}

function isValidUrl(value: string): boolean {
  try {
    const url = new URL(value);
    return url.protocol === 'http:' || url.protocol === 'https:';
  } catch {
    return false;
  }
}

function validateForm(form: FormState): { errors: FormErrors; payload: TickerAdMutation | null } {
  const errors: FormErrors = {};
  const language = normalizeLanguageCode(form.language);
  const message = form.message.trim();
  const messageEn = form.messageEn.trim();
  const messageHi = form.messageHi.trim();
  const messageGu = form.messageGu.trim();
  const url = form.url.trim();
  const startAt = fromLocalInputValue(form.startAtLocal);
  const endAt = fromLocalInputValue(form.endAtLocal);

  if (language === 'all') {
    if (!messageEn) errors.messageEn = 'English message is required.';
    if (!messageHi) errors.messageHi = 'Hindi message is required.';
    if (!messageGu) errors.messageGu = 'Gujarati message is required.';
  } else {
    if (!message) {
      errors.message = 'Message is required.';
    }
  }
  if (url && !isValidUrl(url)) {
    errors.url = 'Enter a valid URL, including http:// or https://.';
  }
  if (!startAt) {
    errors.startAtLocal = 'Start date and time are required.';
  }
  if (!endAt) {
    errors.endAtLocal = 'End date and time are required.';
  }
  if (startAt && endAt && new Date(endAt).getTime() <= new Date(startAt).getTime()) {
    errors.endAtLocal = 'End must be later than start.';
  }

  if (Object.keys(errors).length > 0) {
    return { errors, payload: null };
  }

  const priorityNumber = Number(form.priority);
  const dayParts = normalizeDayPartsCodes(form.dayParts);
  return {
    errors,
    payload:
      language === 'all'
        ? {
          ...(url ? { url } : {}),
          channel: form.channel,
          language: 'all',
          messages: {
            en: messageEn,
            hi: messageHi,
            gu: messageGu,
          },
          startAt,
          endAt,
          dayParts,
          priority: Number.isFinite(priorityNumber) ? Math.round(priorityNumber) : 0,
          frequency: Math.min(10, Math.max(1, Math.round(form.frequency))),
          active: form.active,
        }
        : {
          message,
          ...(url ? { url } : {}),
          channel: form.channel,
          language,
          startAt,
          endAt,
          dayParts,
          priority: Number.isFinite(priorityNumber) ? Math.round(priorityNumber) : 0,
          frequency: Math.min(10, Math.max(1, Math.round(form.frequency))),
          active: form.active,
        },
  };
}

function truncateMessage(value: string, limit = 52): string {
  if (value.length <= limit) return value;
  return `${value.slice(0, limit - 1)}…`;
}

function formatDateTime(iso: string): string {
  if (!iso) return '—';
  const date = new Date(iso);
  if (Number.isNaN(date.getTime())) return iso;
  return date.toLocaleString();
}

function getCurrentDayPart(now: Date): TickerAdDayPart {
  const hour = now.getHours();
  if (hour >= 5 && hour < 12) return 'morning';
  if (hour >= 12 && hour < 17) return 'noon';
  if (hour >= 17 && hour < 21) return 'evening';
  return 'night';
}

function isActiveNow(ad: TickerAd, now: Date): boolean {
  if (!ad.active) return false;

  const startAt = new Date(ad.startAt).getTime();
  const endAt = new Date(ad.endAt).getTime();
  const nowTime = now.getTime();
  if (!Number.isFinite(startAt) || !Number.isFinite(endAt)) return false;
  if (nowTime < startAt || nowTime >= endAt) return false;

  if (ad.dayParts.length === 0) return true;
  return ad.dayParts.includes(getCurrentDayPart(now));
}

function sortAds(items: TickerAd[]): TickerAd[] {
  return items.slice().sort((left, right) => {
    if (right.priority !== left.priority) return right.priority - left.priority;
    if (left.frequency !== right.frequency) return left.frequency - right.frequency;
    return new Date(left.startAt).getTime() - new Date(right.startAt).getTime();
  });
}

function apiErrorDetails(error: unknown): string {
  if (error instanceof AdminApiError) {
    const body = (error as any).body;
    if (!body) return error.message;
    if (typeof body === 'string') return `${error.message} • ${body}`;
    try {
      return `${error.message} • ${JSON.stringify(body)}`;
    } catch {
      return error.message;
    }
  }
  return (error as any)?.message || 'API error';
}

function channelMatches(target: 'breaking' | 'live', channel: TickerAdChannel): boolean {
  return channel === 'both' || channel === target;
}

function adMessageForLanguage(ad: TickerAd, language: 'en' | 'hi' | 'gu'): string {
  if (ad.language !== 'all') return ad.message;
  const fromMessages = ad.messages?.[language];
  return String(fromMessages || ad.message || '').trim();
}

export default function BroadcastCenterTickerAds() {
  const notify = useNotify();
  const submitInFlightRef = useRef(false);
  const [ads, setAds] = useState<TickerAd[]>([]);
  const [loading, setLoading] = useState(true);
  const [refreshing, setRefreshing] = useState(false);
  const [saving, setSaving] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editingAd, setEditingAd] = useState<TickerAd | null>(null);
  const [form, setForm] = useState<FormState>(() => createEmptyForm());
  const [formErrors, setFormErrors] = useState<FormErrors>({});
  const [deleteTarget, setDeleteTarget] = useState<TickerAd | null>(null);
  const [busyIds, setBusyIds] = useState<Record<string, boolean>>({});
  const [lastLoadedAt, setLastLoadedAt] = useState<string | null>(null);
  const [now, setNow] = useState(() => new Date());

  async function loadAds(opts?: { silent?: boolean }) {
    if (!opts?.silent) {
      setRefreshing(true);
    }
    try {
      const items = await listTickerAds();
      setAds(sortAds(items));
      setLastLoadedAt(new Date().toISOString());
    } catch (error) {
      notify.err('Ticker Ads refresh failed', apiErrorDetails(error));
    } finally {
      setRefreshing(false);
      setLoading(false);
    }
  }

  useEffect(() => {
    void loadAds();
  }, []);

  useEffect(() => {
    const timer = window.setInterval(() => setNow(new Date()), 30_000);
    return () => window.clearInterval(timer);
  }, []);

  const previewGroups = useMemo(() => {
    const currentAds = sortAds(ads.filter((ad) => isActiveNow(ad, now)));
    const matchesLang = (ad: TickerAd, lang: 'en' | 'hi' | 'gu') => ad.language === 'all' || ad.language === lang;
    return {
      breaking: {
        en: currentAds.filter((ad) => channelMatches('breaking', ad.channel) && matchesLang(ad, 'en')),
        hi: currentAds.filter((ad) => channelMatches('breaking', ad.channel) && matchesLang(ad, 'hi')),
        gu: currentAds.filter((ad) => channelMatches('breaking', ad.channel) && matchesLang(ad, 'gu')),
      },
      live: {
        en: currentAds.filter((ad) => channelMatches('live', ad.channel) && matchesLang(ad, 'en')),
        hi: currentAds.filter((ad) => channelMatches('live', ad.channel) && matchesLang(ad, 'hi')),
        gu: currentAds.filter((ad) => channelMatches('live', ad.channel) && matchesLang(ad, 'gu')),
      },
    };
  }, [ads, now]);

  function updateForm<K extends keyof FormState>(key: K, value: FormState[K]) {
    setForm((prev) => ({ ...prev, [key]: value }));
    if (key === 'message' || key === 'messageEn' || key === 'messageHi' || key === 'messageGu' || key === 'url' || key === 'startAtLocal' || key === 'endAtLocal') {
      setFormErrors((prev) => {
        const next = { ...prev };
        delete next[key as keyof FormErrors];
        return next;
      });
    }
  }

  function openCreateModal() {
    setEditingAd(null);
    setForm(createEmptyForm());
    setFormErrors({});
    setModalOpen(true);
  }

  function openEditModal(ad: TickerAd) {
    setEditingAd(ad);
    setForm(formFromAd(ad));
    setFormErrors({});
    setModalOpen(true);
  }

  function closeModal() {
    if (saving) return;
    setModalOpen(false);
    setEditingAd(null);
    setFormErrors({});
  }

  async function handleSubmit() {
    if (submitInFlightRef.current || saving) return;
    submitInFlightRef.current = true;
    const result = validateForm(form);
    setFormErrors(result.errors);
    if (!result.payload) {
      submitInFlightRef.current = false;
      return;
    }

    setSaving(true);
    try {
      if (editingAd?.id) {
        await updateTickerAd(editingAd.id, result.payload);
        notify.ok('Ticker ad updated');
      } else {
        await createTickerAd(result.payload);
        notify.ok('Ticker ad created');
      }
      closeModal();
      await loadAds({ silent: true });
    } catch (error) {
      notify.err(editingAd ? 'Ticker ad update failed' : 'Ticker ad create failed', apiErrorDetails(error));
    } finally {
      setSaving(false);
      submitInFlightRef.current = false;
    }
  }

  async function handleDeleteConfirmed() {
    if (!deleteTarget?.id) {
      setDeleteTarget(null);
      return;
    }
    const current = deleteTarget;
    setBusyIds((prev) => ({ ...prev, [current.id]: true }));
    try {
      await deleteTickerAd(current.id);
      notify.ok('Ticker ad deleted');
      setDeleteTarget(null);
      await loadAds({ silent: true });
    } catch (error) {
      notify.err('Ticker ad delete failed', apiErrorDetails(error));
    } finally {
      setBusyIds((prev) => ({ ...prev, [current.id]: false }));
    }
  }

  async function handleToggle(ad: TickerAd, nextActive: boolean) {
    if (!ad.id) return;
    setBusyIds((prev) => ({ ...prev, [ad.id]: true }));
    try {
      await updateTickerAd(
        ad.id,
        ad.language === 'all'
          ? {
            ...(ad.url ? { url: ad.url } : {}),
            channel: ad.channel,
            language: 'all',
            messages: {
              en: String(ad.messages?.en || ad.message || '').trim(),
              hi: String(ad.messages?.hi || ad.message || '').trim(),
              gu: String(ad.messages?.gu || ad.message || '').trim(),
            },
            dayParts: ad.dayParts,
            startAt: ad.startAt,
            endAt: ad.endAt,
            priority: ad.priority,
            frequency: ad.frequency,
            active: nextActive,
          }
          : {
            message: ad.message,
            ...(ad.url ? { url: ad.url } : {}),
            channel: ad.channel,
            language: ad.language,
            dayParts: ad.dayParts,
            startAt: ad.startAt,
            endAt: ad.endAt,
            priority: ad.priority,
            frequency: ad.frequency,
            active: nextActive,
          },
      );
      notify.ok(nextActive ? 'Ticker ad enabled' : 'Ticker ad disabled');
      await loadAds({ silent: true });
    } catch (error) {
      notify.err('Ticker ad toggle failed', apiErrorDetails(error));
    } finally {
      setBusyIds((prev) => ({ ...prev, [ad.id]: false }));
    }
  }

  return (
    <div className="space-y-6">
      <section className="rounded-2xl border border-slate-200 bg-white p-5 dark:border-slate-700 dark:bg-slate-900">
        <div className="flex flex-col gap-4 lg:flex-row lg:items-start lg:justify-between">
          <div>
            <h2 className="text-lg font-semibold text-slate-900 dark:text-white">Ticker Ads (Paid Scroll)</h2>
            <p className="mt-1 text-sm text-slate-600 dark:text-slate-300">
              Separate paid scroll manager for scheduled ticker lines. Breaking and Live Updates 24h items are unchanged.
            </p>
            {lastLoadedAt ? (
              <div className="mt-2 text-xs text-slate-500 dark:text-slate-400">Last refreshed {formatDateTime(lastLoadedAt)}</div>
            ) : null}
          </div>

          <div className="flex flex-wrap items-center gap-3">
            <button
              type="button"
              className="rounded-lg border border-slate-200 bg-white px-4 py-2 text-sm font-semibold text-slate-900 hover:bg-slate-50 disabled:opacity-50 dark:border-slate-700 dark:bg-slate-900 dark:text-white dark:hover:bg-slate-800"
              disabled={refreshing}
              onClick={() => void loadAds()}
            >
              {refreshing ? 'Refreshing…' : 'Refresh list'}
            </button>
            <button
              type="button"
              className="rounded-lg bg-slate-900 px-4 py-2 text-sm font-semibold text-white hover:bg-slate-800 dark:bg-white dark:text-slate-900 dark:hover:bg-slate-200"
              onClick={openCreateModal}
            >
              Create ticker ad
            </button>
          </div>
        </div>
      </section>

      <section className="rounded-2xl border border-slate-200 bg-white p-5 dark:border-slate-700 dark:bg-slate-900">
        <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
          <div>
            <div className="text-sm font-semibold text-slate-900 dark:text-white">Preview (Now)</div>
            <div className="mt-1 text-xs text-slate-500 dark:text-slate-400">
              Active window at {now.toLocaleString()} based on channel, language, schedule, and day parts.
            </div>
          </div>
          <div className="rounded-full bg-slate-100 px-3 py-1 text-xs font-semibold text-slate-700 dark:bg-slate-800 dark:text-slate-200">
            Current day part: {getCurrentDayPart(now)}
          </div>
        </div>

        <div className="mt-4 grid grid-cols-1 gap-4 xl:grid-cols-2">
          {(['breaking', 'live'] as const).map((channel) => (
            <div key={channel} className="rounded-xl border border-slate-200 p-4 dark:border-slate-700">
              <div className="text-xs font-semibold uppercase tracking-wide text-slate-500 dark:text-slate-400">
                {channel === 'breaking' ? 'Breaking' : 'Live Updates'}
              </div>
              <div className="mt-3 grid grid-cols-1 gap-3 md:grid-cols-3">
                {(['en', 'hi', 'gu'] as const).map((language) => {
                  const items = previewGroups[channel][language];
                  return (
                    <div key={`${channel}-${language}`} className="rounded-lg border border-slate-200 bg-slate-50 p-3 dark:border-slate-700 dark:bg-slate-950">
                      <div className="mb-2 text-xs font-semibold text-slate-700 dark:text-slate-200">
                        {language === 'en' ? 'English' : language === 'hi' ? 'Hindi' : 'Gujarati'}
                      </div>
                      {items.length === 0 ? (
                        <div className="text-xs text-slate-500 dark:text-slate-400">No active paid scroll lines right now.</div>
                      ) : (
                        <div className="space-y-2">
                          {items.map((ad) => (
                            <div key={`${channel}-${language}-${ad.id || ad.message}-${ad.startAt}`} className="rounded-lg border border-slate-200 bg-white p-2 text-xs dark:border-slate-800 dark:bg-slate-900">
                              <div className="font-medium text-slate-900 dark:text-white">{adMessageForLanguage(ad, language)}</div>
                              <div className="mt-1 text-slate-500 dark:text-slate-400">P{ad.priority} • Every {ad.frequency} items</div>
                            </div>
                          ))}
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            </div>
          ))}
        </div>
      </section>

      <section className="rounded-2xl border border-slate-200 bg-white p-5 dark:border-slate-700 dark:bg-slate-900">
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-slate-200 text-sm dark:divide-slate-700">
            <thead>
              <tr className="text-left text-xs uppercase tracking-wide text-slate-500 dark:text-slate-400">
                <th className="px-3 py-3 font-semibold">Message</th>
                <th className="px-3 py-3 font-semibold">Channel</th>
                <th className="px-3 py-3 font-semibold">Language</th>
                <th className="px-3 py-3 font-semibold">DayParts</th>
                <th className="px-3 py-3 font-semibold">Start → End</th>
                <th className="px-3 py-3 font-semibold">Active</th>
                <th className="px-3 py-3 font-semibold">Priority</th>
                <th className="px-3 py-3 font-semibold">Frequency</th>
                <th className="px-3 py-3 font-semibold">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-200 dark:divide-slate-700">
              {ads.length === 0 ? (
                <tr>
                  <td colSpan={9} className="px-3 py-8 text-center text-sm text-slate-500 dark:text-slate-400">
                    {loading ? 'Loading ticker ads…' : 'No paid ticker ads found.'}
                  </td>
                </tr>
              ) : (
                ads.map((ad) => {
                  const busy = !!busyIds[ad.id];
                  return (
                    <tr key={ad.id || `${ad.message}-${ad.startAt}`} className="align-top text-slate-700 dark:text-slate-200">
                      <td className="px-3 py-3">
                        <div className="max-w-xs truncate font-medium text-slate-900 dark:text-white" title={ad.message}>
                          {truncateMessage(ad.message)}
                        </div>
                        {ad.url ? (
                          <div className="mt-1 max-w-xs truncate text-xs text-slate-500 dark:text-slate-400" title={ad.url}>
                            {ad.url}
                          </div>
                        ) : null}
                      </td>
                      <td className="px-3 py-3">
                        <span className="rounded-full bg-slate-100 px-2.5 py-1 text-xs font-semibold text-slate-700 dark:bg-slate-800 dark:text-slate-200">
                          {ad.channel}
                        </span>
                      </td>
                      <td className="px-3 py-3 uppercase">{ad.language}</td>
                      <td className="px-3 py-3">
                        <div className="flex max-w-[14rem] flex-wrap gap-1">
                          {ad.dayParts.length === 0 ? (
                            <span className="rounded-full bg-emerald-50 px-2.5 py-1 text-xs font-semibold text-emerald-700 dark:bg-emerald-950/40 dark:text-emerald-200">
                              All day
                            </span>
                          ) : (
                            ad.dayParts.map((dayPart) => (
                              <span key={`${ad.id}-${dayPart}`} className="rounded-full bg-slate-100 px-2.5 py-1 text-xs font-semibold text-slate-700 dark:bg-slate-800 dark:text-slate-200">
                                {dayPart}
                              </span>
                            ))
                          )}
                        </div>
                      </td>
                      <td className="px-3 py-3 text-xs text-slate-600 dark:text-slate-300">
                        <div>{formatDateTime(ad.startAt)}</div>
                        <div className="mt-1">{formatDateTime(ad.endAt)}</div>
                      </td>
                      <td className="px-3 py-3">
                        <div className="flex items-center gap-3">
                          <Switch checked={ad.active} onCheckedChange={(next) => void handleToggle(ad, next)} disabled={busy} label="Toggle active status" />
                          <span className="text-xs font-semibold text-slate-500 dark:text-slate-400">{ad.active ? 'ON' : 'OFF'}</span>
                        </div>
                      </td>
                      <td className="px-3 py-3 font-semibold text-slate-900 dark:text-white">{ad.priority}</td>
                      <td className="px-3 py-3 text-xs text-slate-600 dark:text-slate-300">Every {ad.frequency} items</td>
                      <td className="px-3 py-3">
                        <div className="flex flex-wrap gap-2">
                          <button
                            type="button"
                            className="rounded-lg border border-slate-200 bg-white px-3 py-1.5 text-xs font-semibold text-slate-900 hover:bg-slate-50 disabled:opacity-50 dark:border-slate-700 dark:bg-slate-900 dark:text-white dark:hover:bg-slate-800"
                            disabled={busy}
                            onClick={() => openEditModal(ad)}
                          >
                            Edit
                          </button>
                          <button
                            type="button"
                            className="rounded-lg border border-red-200 bg-red-50 px-3 py-1.5 text-xs font-semibold text-red-700 hover:bg-red-100 disabled:opacity-50 dark:border-red-900/50 dark:bg-red-950/40 dark:text-red-200 dark:hover:bg-red-900/40"
                            disabled={busy}
                            onClick={() => setDeleteTarget(ad)}
                          >
                            Delete
                          </button>
                        </div>
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </section>

      {modalOpen ? (
        <div className="fixed inset-0 z-50 bg-black/40 p-4" role="dialog" aria-modal="true">
          <div className="mx-auto max-h-[92vh] w-full max-w-3xl overflow-y-auto rounded-2xl border border-slate-200 bg-white shadow-xl dark:border-slate-700 dark:bg-slate-900">
            <div className="flex items-start justify-between gap-4 border-b border-slate-200 px-5 py-4 dark:border-slate-700">
              <div>
                <div className="text-lg font-semibold text-slate-900 dark:text-white">
                  {editingAd ? 'Edit ticker ad' : 'Create ticker ad'}
                </div>
                <div className="mt-1 text-sm text-slate-500 dark:text-slate-400">
                  Configure the paid scroll line, schedule, language, and injection frequency.
                </div>
              </div>
              <button
                type="button"
                className="rounded-lg border border-slate-200 px-3 py-1.5 text-sm font-semibold text-slate-600 hover:bg-slate-50 dark:border-slate-700 dark:text-slate-200 dark:hover:bg-slate-800"
                onClick={closeModal}
              >
                Close
              </button>
            </div>

            <div className="space-y-5 px-5 py-4">
              <div>
                {form.language === 'all' ? (
                  <div className="space-y-4">
                    <div>
                      <div className="mb-2 flex items-center justify-between">
                        <label className="text-sm font-semibold text-slate-900 dark:text-white">Message (English)</label>
                        <div className="text-xs text-slate-500 dark:text-slate-400">{form.messageEn.length}/140</div>
                      </div>
                      <textarea
                        value={form.messageEn}
                        maxLength={140}
                        rows={3}
                        onChange={(event) => updateForm('messageEn', event.target.value)}
                        className="w-full rounded-xl border border-slate-200 bg-white px-3 py-2 text-sm text-slate-900 outline-none ring-0 placeholder:text-slate-400 focus:border-slate-400 dark:border-slate-700 dark:bg-slate-950 dark:text-white"
                        placeholder="Sponsored ticker message (EN)"
                      />
                      {formErrors.messageEn ? <div className="mt-2 text-xs text-red-600 dark:text-red-300">{formErrors.messageEn}</div> : null}
                    </div>

                    <div>
                      <div className="mb-2 flex items-center justify-between">
                        <label className="text-sm font-semibold text-slate-900 dark:text-white">Message (Hindi)</label>
                        <div className="text-xs text-slate-500 dark:text-slate-400">{form.messageHi.length}/140</div>
                      </div>
                      <textarea
                        value={form.messageHi}
                        maxLength={140}
                        rows={3}
                        onChange={(event) => updateForm('messageHi', event.target.value)}
                        className="w-full rounded-xl border border-slate-200 bg-white px-3 py-2 text-sm text-slate-900 outline-none ring-0 placeholder:text-slate-400 focus:border-slate-400 dark:border-slate-700 dark:bg-slate-950 dark:text-white"
                        placeholder="Sponsored ticker message (HI)"
                      />
                      {formErrors.messageHi ? <div className="mt-2 text-xs text-red-600 dark:text-red-300">{formErrors.messageHi}</div> : null}
                    </div>

                    <div>
                      <div className="mb-2 flex items-center justify-between">
                        <label className="text-sm font-semibold text-slate-900 dark:text-white">Message (Gujarati)</label>
                        <div className="text-xs text-slate-500 dark:text-slate-400">{form.messageGu.length}/140</div>
                      </div>
                      <textarea
                        value={form.messageGu}
                        maxLength={140}
                        rows={3}
                        onChange={(event) => updateForm('messageGu', event.target.value)}
                        className="w-full rounded-xl border border-slate-200 bg-white px-3 py-2 text-sm text-slate-900 outline-none ring-0 placeholder:text-slate-400 focus:border-slate-400 dark:border-slate-700 dark:bg-slate-950 dark:text-white"
                        placeholder="Sponsored ticker message (GU)"
                      />
                      {formErrors.messageGu ? <div className="mt-2 text-xs text-red-600 dark:text-red-300">{formErrors.messageGu}</div> : null}
                    </div>
                  </div>
                ) : (
                  <div>
                    <div className="mb-2 flex items-center justify-between">
                      <label className="text-sm font-semibold text-slate-900 dark:text-white">Message</label>
                      <div className="text-xs text-slate-500 dark:text-slate-400">{form.message.length}/140</div>
                    </div>
                    <textarea
                      value={form.message}
                      maxLength={140}
                      rows={3}
                      onChange={(event) => updateForm('message', event.target.value)}
                      className="w-full rounded-xl border border-slate-200 bg-white px-3 py-2 text-sm text-slate-900 outline-none ring-0 placeholder:text-slate-400 focus:border-slate-400 dark:border-slate-700 dark:bg-slate-950 dark:text-white"
                      placeholder="Sponsored ticker message"
                    />
                    {formErrors.message ? <div className="mt-2 text-xs text-red-600 dark:text-red-300">{formErrors.message}</div> : null}
                  </div>
                )}
              </div>

              <div>
                <label className="mb-2 block text-sm font-semibold text-slate-900 dark:text-white">URL (optional)</label>
                <input
                  type="url"
                  value={form.url}
                  onChange={(event) => updateForm('url', event.target.value)}
                  className="w-full rounded-xl border border-slate-200 bg-white px-3 py-2 text-sm text-slate-900 outline-none placeholder:text-slate-400 focus:border-slate-400 dark:border-slate-700 dark:bg-slate-950 dark:text-white"
                  placeholder="https://example.com/offer"
                />
                {formErrors.url ? <div className="mt-2 text-xs text-red-600 dark:text-red-300">{formErrors.url}</div> : null}
              </div>

              <div className="grid grid-cols-1 gap-4 md:grid-cols-2">
                <div>
                  <label className="mb-2 block text-sm font-semibold text-slate-900 dark:text-white">Channel</label>
                  <select
                    value={form.channel}
                    onChange={(event) => updateForm('channel', event.target.value as TickerAdChannel)}
                    className="w-full rounded-xl border border-slate-200 bg-white px-3 py-2 text-sm text-slate-900 focus:border-slate-400 dark:border-slate-700 dark:bg-slate-950 dark:text-white"
                  >
                    {CHANNEL_OPTIONS.map((option) => (
                      <option key={option.value} value={option.value}>{option.label}</option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="mb-2 block text-sm font-semibold text-slate-900 dark:text-white">Language</label>
                  <select
                    value={form.language}
                    onChange={(event) => {
                      const nextLanguage = normalizeLanguageCode(event.target.value);
                      setFormErrors((prev) => {
                        const next = { ...prev };
                        delete next.message;
                        delete next.messageEn;
                        delete next.messageHi;
                        delete next.messageGu;
                        return next;
                      });
                      setForm((prev) => {
                        if (nextLanguage === prev.language) return prev;

                        if (nextLanguage === 'all' && prev.language !== 'all') {
                          return {
                            ...prev,
                            language: nextLanguage,
                            messageEn: prev.messageEn || prev.message,
                          };
                        }

                        if (nextLanguage !== 'all' && prev.language === 'all') {
                          const nextMessage = nextLanguage === 'en'
                            ? prev.messageEn
                            : nextLanguage === 'hi'
                              ? prev.messageHi
                              : prev.messageGu;
                          return {
                            ...prev,
                            language: nextLanguage,
                            message: prev.message || nextMessage || prev.messageEn || prev.messageHi || prev.messageGu,
                          };
                        }

                        return { ...prev, language: nextLanguage };
                      });
                    }}
                    className="w-full rounded-xl border border-slate-200 bg-white px-3 py-2 text-sm text-slate-900 focus:border-slate-400 dark:border-slate-700 dark:bg-slate-950 dark:text-white"
                  >
                    {LANGUAGE_OPTIONS.map((option) => (
                      <option key={option.value} value={option.value}>{option.label}</option>
                    ))}
                  </select>
                </div>
              </div>

              <div className="grid grid-cols-1 gap-4 md:grid-cols-2">
                <div>
                  <label className="mb-2 block text-sm font-semibold text-slate-900 dark:text-white">Start datetime</label>
                  <input
                    type="datetime-local"
                    value={form.startAtLocal}
