        };
        if (!cancelled) setStats(norm);
      } catch (e: any) {
        const status = e?.response?.status;
        if (status === 401) {
          try { toast.error('Session expired. Please log in again'); } catch {}
        }
        if (!cancelled) setStatsError('Failed to load stats');
